import { Guest, ContactMessage } from '../types';

// Keys for local storage
const RSVP_KEY = 'wedding_rsvps';
const MSG_KEY = 'wedding_messages';

// Helper to simulate delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const saveRSVP = async (guest: Omit<Guest, 'id' | 'createdAt'>): Promise<boolean> => {
  await delay(800); // Simulate network request
  try {
    const rsvps: Guest[] = JSON.parse(localStorage.getItem(RSVP_KEY) || '[]');
    const newGuest: Guest = {
      ...guest,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date().toISOString(),
    };
    rsvps.push(newGuest);
    localStorage.setItem(RSVP_KEY, JSON.stringify(rsvps));
    return true;
  } catch (error) {
    console.error("Error saving RSVP", error);
    return false;
  }
};

export const getRSVPs = async (): Promise<Guest[]> => {
  await delay(500);
  return JSON.parse(localStorage.getItem(RSVP_KEY) || '[]');
};

export const saveMessage = async (msg: Omit<ContactMessage, 'id' | 'createdAt'>): Promise<boolean> => {
  await delay(800);
  try {
    const messages: ContactMessage[] = JSON.parse(localStorage.getItem(MSG_KEY) || '[]');
    const newMessage: ContactMessage = {
      ...msg,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date().toISOString(),
    };
    messages.push(newMessage);
    localStorage.setItem(MSG_KEY, JSON.stringify(messages));
    return true;
  } catch (error) {
    console.error("Error saving message", error);
    return false;
  }
};

export const getMessages = async (): Promise<ContactMessage[]> => {
  await delay(500);
  return JSON.parse(localStorage.getItem(MSG_KEY) || '[]');
};

