import React, { useState } from 'react';
import { Send, CheckCircle, Loader2 } from 'lucide-react';
import { saveRSVP } from '../services/storage';

const RSVP: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    guestsCount: 1,
    message: ''
  });

  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'guestsCount' ? parseInt(value) : value
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('loading');

    const success = await saveRSVP(formData);

    if (success) {
      setStatus('success');
      setFormData({ name: '', email: '', phone: '', guestsCount: 1, message: '' });
    } else {
      setStatus('error');
    }
  };

  return (
    <section id="rsvp" className="py-20 bg-cover bg-center relative" style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1469334031218-e382a71b716b?ixlib=rb-1.2.1&auto=format&fit=crop&w=1950&q=80")' }}>
      <div className="absolute inset-0 bg-wedding-primary/90"></div>

      <div className="relative max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="bg-white rounded-2xl shadow-2xl p-8 md:p-12">
          <div className="text-center mb-10">
            <h2 className="text-4xl font-cursive text-wedding-primary mb-2">আপনার উপস্থিতি কামনা করি</h2>
            <p className="text-gray-600">অনুগ্রহ করে নিচের ফর্মটি পূরণ করে কনফার্ম করুন</p>
          </div>

          {status === 'success' ? (
            <div className="text-center py-12 animate-fade-in">
              <div className="flex justify-center mb-4">
                <CheckCircle size={64} className="text-green-500" />
              </div>
              <h3 className="text-2xl font-bold text-gray-800 mb-2">ধন্যবাদ!</h3>
              <p className="text-gray-600">আপনার RSVP আমরা পেয়েছি। অনুষ্ঠানে দেখা হবে!</p>
              <button 
                onClick={() => setStatus('idle')}
                className="mt-6 text-wedding-primary underline"
              >
                অন্য কাউকে যুক্ত করুন
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-6">
