        <div className="bg-white rounded-2xl shadow-2xl p-8 md:p-12 overflow-hidden">

          {status === 'success' ? (
            <div className="animate-fade-in flex flex-col items-center">
              <div className="mb-6">
                <CheckCircle size={64} className="text-green-500 animate-bounce" />
