              <h3 className="text-3xl font-bold text-gray-800 mb-2">ধন্যবাদ!</h3>
              <p className="text-gray-600 mb-8 text-center">আপনার RSVP আমরা পেয়েছি। আপনার জন্য এই কার্ডটি:</p>

              {/* Invitation Ticket Card */}
              <div className="bg-gradient-to-r from-wedding-bg to-white border-2 border-wedding-primary/20 rounded-xl p-6 w-full max-w-md shadow-inner relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 opacity-10">
                   <Ticket size={100} className="text-wedding-primary" />
                </div>

                <div className="text-center border-b-2 border-dashed border-wedding-primary/30 pb-4 mb-4">
