import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getRSVPs, getMessages, getWebsiteConfig, saveWebsiteConfig } from '../services/storage';
import { Guest, ContactMessage, WebsiteConfig, EventItem } from '../types';
import { Users, MessageSquare, LogOut, Edit, Save, Trash2, Plus, Upload } from 'lucide-react';

const AdminDashboard: React.FC = () => {
  const [rsvps, setRsvps] = useState<Guest[]>([]);
  const [messages, setMessages] = useState<ContactMessage[]>([]);
  const [config, setConfig] = useState<WebsiteConfig | null>(null);
  const [activeTab, setActiveTab] = useState<'rsvp' | 'messages' | 'content'>('rsvp');
  const [saving, setSaving] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const isAdmin = localStorage.getItem('isAdmin');
    if (!isAdmin) {
      navigate('/admin');
      return;
    }

    const fetchData = async () => {
      const rsvpData = await getRSVPs();
      const msgData = await getMessages();
      const configData = await getWebsiteConfig();
      setRsvps(rsvpData);
      setMessages(msgData);
      setConfig(configData);
    };
    fetchData();
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('isAdmin');
    navigate('/admin');
  };

  const handleConfigChange = (section: keyof WebsiteConfig, field: string, value: any, index?: number) => {
    if (!config) return;

    setConfig(prev => {
      if (!prev) return null;
      const newConfig = { ...prev };

      if (section === 'stories' && typeof index === 'number') {
        // @ts-ignore
        newConfig.stories[index] = { ...newConfig.stories[index], [field]: value };
      } else if (section === 'events' && typeof index === 'number') {
        // @ts-ignore
        newConfig.events[index] = { ...newConfig.events[index], [field]: value };
      } else if (section === 'hero' || section === 'contact') {
        // @ts-ignore
        newConfig[section] = { ...newConfig[section], [field]: value };
      } else if (section === 'countdownDate') {
         // @ts-ignore
         newConfig.countdownDate = value;
      }
      return newConfig;
    });
  };

  // Helper to compress image
  const compressImage = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_WIDTH = 800;
          const MAX_HEIGHT = 800;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_WIDTH) {
              height *= MAX_WIDTH / width;
              width = MAX_WIDTH;
            }
          } else {
            if (height > MAX_HEIGHT) {
              width *= MAX_HEIGHT / height;
              height = MAX_HEIGHT;
            }
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(img, 0, 0, width, height);
          resolve(canvas.toDataURL('image/jpeg', 0.6)); // Compress to JPEG with 0.6 quality
        };
        img.onerror = (error) => reject(error);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, section: string, index?: number) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const base64String = await compressImage(file);

      if (section === 'gallery') {
         setConfig(prev => {
             if(!prev) return null;
             return { ...prev, gallery: [...prev.gallery, base64String] }
         });
      } else if (section === 'hero') {
         handleConfigChange('hero', 'image', base64String);
      } else if (section === 'stories' && typeof index === 'number') {
         handleConfigChange('stories', 'image', base64String, index);
      }
    } catch (error) {
      console.error("Error processing image", error);
      alert("ছবি প্রসেস করতে সমস্যা হয়েছে। অন্য ছবি চেষ্টা করুন।");
    }
  };

  const removeGalleryImage = (index: number) => {
    setConfig(prev => {
        if(!prev) return null;
        const newGallery = prev.gallery.filter((_, i) => i !== index);
        return { ...prev, gallery: newGallery };
    });
  };

  const saveContent = async () => {
    if (!config) return;
    setSaving(true);
    const success = await saveWebsiteConfig(config);
    setSaving(false);

    if (success) {
      alert('পরিবর্তন সংরক্ষণ করা হয়েছে!');
    } else {
      alert('সংরক্ষণ ব্যর্থ হয়েছে! মেমোরি ফুল (Quota Exceeded)। অনুগ্রহ করে গ্যালারি থেকে কিছু ছবি ডিলিট করুন অথবা ছোট সাইজের ছবি ব্যবহার করুন।');
    }
  };

  const totalGuests = rsvps.reduce((acc, curr) => acc + curr.guestsCount, 0);

  if (!config) return <div className="p-10 text-center">Loading...</div>;

  return (
    <div className="min-h-screen bg-gray-50 font-bengali">
      {/* Top Bar */}
      <header className="bg-white shadow sticky top-0 z-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <h1 className="text-xl md:text-2xl font-bold text-gray-800">অ্যাডমিন ড্যাশবোর্ড</h1>
          <button 
            onClick={handleLogout}
            className="flex items-center gap-2 text-red-600 hover:text-red-700 font-medium"
          >
            <LogOut size={18} /> লগআউট
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-wedding-primary flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">মোট RSVP</p>
              <h3 className="text-3xl font-bold text-gray-800">{rsvps.length}</h3>
              <p className="text-sm text-gray-600 mt-1">মোট অতিথি: {totalGuests} জন</p>
            </div>
            <div className="p-4 bg-wedding-bg rounded-full text-wedding-primary">
              <Users size={24} />
            </div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-blue-500 flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">নতুন বার্তা</p>
              <h3 className="text-3xl font-bold text-gray-800">{messages.length}</h3>
            </div>
            <div className="p-4 bg-blue-50 rounded-full text-blue-500">
              <MessageSquare size={24} />
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="bg-white rounded-xl shadow-sm overflow-hidden min-h-[500px]">
          <div className="border-b border-gray-200">
            <nav className="flex -mb-px overflow-x-auto">
              <button
                onClick={() => setActiveTab('rsvp')}
                className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${
                  activeTab === 'rsvp'
                    ? 'border-wedding-primary text-wedding-primary'
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
              >
                <Users size={16} /> RSVP তালিকা
              </button>
              <button
                onClick={() => setActiveTab('messages')}
                className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${
                  activeTab === 'messages'
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
              >
                <MessageSquare size={16} /> বার্তাসমূহ
              </button>
              <button
                onClick={() => setActiveTab('content')}
                className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${
                  activeTab === 'content'
                    ? 'border-green-500 text-green-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
              >
                <Edit size={16} /> ওয়েবসাইট এডিট
              </button>
            </nav>
          </div>

          <div className="p-6">
            {activeTab === 'rsvp' && (
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
