import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getRSVPs, getMessages, getWebsiteConfig, saveWebsiteConfig } from '../services/storage';
import { Guest, ContactMessage, WebsiteConfig, EventItem } from '../types';
import { Users, MessageSquare, LogOut, Edit, Save, Trash2, Plus, Upload } from 'lucide-react';

const AdminDashboard: React.FC = () => {
  const [rsvps, setRsvps] = useState<Guest[]>([]);
  const [messages, setMessages] = useState<ContactMessage[]>([]);
  const [config, setConfig] = useState<WebsiteConfig | null>(null);
  const [activeTab, setActiveTab] = useState<'rsvp' | 'messages' | 'content'>('rsvp');
  const [saving, setSaving] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const isAdmin = localStorage.getItem('isAdmin');
    if (!isAdmin) {
      navigate('/admin');
      return;
    }

    const fetchData = async () => {
      const rsvpData = await getRSVPs();
      const msgData = await getMessages();
      const configData = await getWebsiteConfig();
      setRsvps(rsvpData);
      setMessages(msgData);
      setConfig(configData);
    };
    fetchData();
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('isAdmin');
    navigate('/admin');
  };

  const handleConfigChange = (section: keyof WebsiteConfig, field: string, value: any, index?: number) => {
    if (!config) return;

    setConfig(prev => {
      if (!prev) return null;
      const newConfig = { ...prev };

      if (section === 'stories' && typeof index === 'number') {
        // @ts-ignore
        newConfig.stories[index] = { ...newConfig.stories[index], [field]: value };
      } else if (section === 'events' && typeof index === 'number') {
        // @ts-ignore
        newConfig.events[index] = { ...newConfig.events[index], [field]: value };
      } else if (section === 'hero' || section === 'contact') {
        // @ts-ignore
        newConfig[section] = { ...newConfig[section], [field]: value };
      } else if (section === 'countdownDate') {
         // @ts-ignore
         newConfig.countdownDate = value;
      }
      return newConfig;
    });
  };

  // Helper to compress image
  const compressImage = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const MAX_WIDTH = 800;
          const MAX_HEIGHT = 800;
          let width = img.width;
          let height = img.height;

          if (width > height) {
            if (width > MAX_WIDTH) {
              height *= MAX_WIDTH / width;
              width = MAX_WIDTH;
            }
          } else {
            if (height > MAX_HEIGHT) {
              width *= MAX_HEIGHT / height;
              height = MAX_HEIGHT;
            }
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext('2d');
          ctx?.drawImage(img, 0, 0, width, height);
          resolve(canvas.toDataURL('image/jpeg', 0.6)); // Compress to JPEG with 0.6 quality
        };
        img.onerror = (error) => reject(error);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, section: string, index?: number) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const base64String = await compressImage(file);

      if (section === 'gallery') {
         setConfig(prev => {
             if(!prev) return null;
             return { ...prev, gallery: [...prev.gallery, base64String] }
         });
      } else if (section === 'hero') {
         handleConfigChange('hero', 'image', base64String);
      } else if (section === 'stories' && typeof index === 'number') {
         handleConfigChange('stories', 'image', base64String, index);
      }
    } catch (error) {
      console.error("Error processing image", error);
      alert("ছবি প্রসেস করতে সমস্যা হয়েছে। অন্য ছবি চেষ্টা করুন।");
    }
  };

  const removeGalleryImage = (index: number) => {
    setConfig(prev => {
        if(!prev) return null;
        const newGallery = prev.gallery.filter((_, i) => i !== index);
        return { ...prev, gallery: newGallery };
    });
  };

  const saveContent = async () => {
    if (!config) return;
    setSaving(true);
    const success = await saveWebsiteConfig(config);
    setSaving(false);

    if (success) {
      alert('পরিবর্তন সংরক্ষণ করা হয়েছে!');
    } else {
      alert('সংরক্ষণ ব্যর্থ হয়েছে! মেমোরি ফুল (Quota Exceeded)। অনুগ্রহ করে গ্যালারি থেকে কিছু ছবি ডিলিট করুন অথবা ছোট সাইজের ছবি ব্যবহার করুন।');
    }
  };

  const totalGuests = rsvps.reduce((acc, curr) => acc + curr.guestsCount, 0);

  if (!config) return <div className="p-10 text-center">Loading...</div>;

  return (
    <div className="min-h-screen bg-gray-50 font-bengali">
      {/* Top Bar */}
      <header className="bg-white shadow sticky top-0 z-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <h1 className="text-xl md:text-2xl font-bold text-gray-800">অ্যাডমিন ড্যাশবোর্ড</h1>
          <button 
            onClick={handleLogout}
            className="flex items-center gap-2 text-red-600 hover:text-red-700 font-medium"
          >
            <LogOut size={18} /> লগআউট
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-wedding-primary flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">মোট RSVP</p>
              <h3 className="text-3xl font-bold text-gray-800">{rsvps.length}</h3>
              <p className="text-sm text-gray-600 mt-1">মোট অতিথি: {totalGuests} জন</p>
            </div>
            <div className="p-4 bg-wedding-bg rounded-full text-wedding-primary">
              <Users size={24} />
            </div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-blue-500 flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">নতুন বার্তা</p>
              <h3 className="text-3xl font-bold text-gray-800">{messages.length}</h3>
            </div>
            <div className="p-4 bg-blue-50 rounded-full text-blue-500">
              <MessageSquare size={24} />
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="bg-white rounded-xl shadow-sm overflow-hidden min-h-[500px]">
          <div className="border-b border-gray-200">
            <nav className="flex -mb-px overflow-x-auto">
              <button
                onClick={() => setActiveTab('rsvp')}
                className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${
                  activeTab === 'rsvp'
                    ? 'border-wedding-primary text-wedding-primary'
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
              >
                <Users size={16} /> RSVP তালিকা
              </button>
              <button
                onClick={() => setActiveTab('messages')}
                className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${
                  activeTab === 'messages'
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
              >
                <MessageSquare size={16} /> বার্তাসমূহ
              </button>
              <button
                onClick={() => setActiveTab('content')}
                className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${
                  activeTab === 'content'
                    ? 'border-green-500 text-green-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
              >
                <Edit size={16} /> ওয়েবসাইট এডিট
              </button>
            </nav>
          </div>

          <div className="p-6">
            {activeTab === 'rsvp' && (
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">নাম</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">ফোন</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">অতিথি সংখ্যা</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">বার্তা</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">সময়</th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200">
                    {rsvps.length === 0 ? (
                      <tr>
                        <td colSpan={5} className="px-6 py-4 text-center text-gray-500">এখনও কোন RSVP পাওয়া যায়নি।</td>
                      </tr>
                    ) : (
                      rsvps.map((guest) => (
                        <tr key={guest.id} className="hover:bg-gray-50">
                          <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{guest.name}</td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{guest.phone}</td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-bold">{guest.guestsCount}</td>
                          <td className="px-6 py-4 text-sm text-gray-500 max-w-xs truncate">{guest.message || '-'}</td>
                          <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                            {new Date(guest.createdAt).toLocaleDateString()}
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>
            )}

            {activeTab === 'messages' && (
              <div className="space-y-4">
                {messages.length === 0 ? (
                  <p className="text-center text-gray-500">কোন বার্তা নেই।</p>
                ) : (
                  messages.map((msg) => (
                    <div key={msg.id} className="border border-gray-200 rounded-lg p-4 hover:bg-gray-50 transition-colors">
                      <div className="flex justify-between items-start mb-2">
                        <div>
                          <h4 className="font-bold text-gray-800">{msg.name}</h4>
                          <p className="text-sm text-gray-500">{msg.email}</p>
                        </div>
                        <span className="text-xs text-gray-400">{new Date(msg.createdAt).toLocaleDateString()}</span>
                      </div>
                      <p className="text-gray-700 bg-gray-50 p-3 rounded-md">{msg.message}</p>
                    </div>
                  ))
                )}
              </div>
            )}

            {activeTab === 'content' && (
              <div className="space-y-8 animate-fade-in">
                <div className="flex justify-end sticky top-0 bg-white/90 p-4 z-10 border-b">
                  <button 
                    onClick={saveContent}
                    disabled={saving}
                    className="flex items-center gap-2 bg-green-600 text-white px-6 py-2 rounded-lg hover:bg-green-700 disabled:opacity-50"
                  >
                    <Save size={18} /> {saving ? 'সংরক্ষণ হচ্ছে...' : 'পরিবর্তন সংরক্ষণ করুন'}
                  </button>
                </div>

                {/* Hero Section */}
                <section className="border p-4 rounded-lg bg-gray-50">
                   <h3 className="text-lg font-bold mb-4 border-b pb-2">হিরো সেকশন (Hero)</h3>
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div>
                       <label className="block text-sm font-medium mb-1">বর এর নাম</label>
                       <input type="text" value={config.hero.groomName} onChange={(e) => handleConfigChange('hero', 'groomName', e.target.value)} className="w-full p-2 border rounded" />
                     </div>
                     <div>
                       <label className="block text-sm font-medium mb-1">কনে এর নাম</label>
                       <input type="text" value={config.hero.brideName} onChange={(e) => handleConfigChange('hero', 'brideName', e.target.value)} className="w-full p-2 border rounded" />
                     </div>
                     <div>
                       <label className="block text-sm font-medium mb-1">তারিখ (ডিসপ্লে)</label>
                       <input type="text" value={config.hero.date} onChange={(e) => handleConfigChange('hero', 'date', e.target.value)} className="w-full p-2 border rounded" />
                     </div>
                     <div>
                       <label className="block text-sm font-medium mb-1">লোকেশন</label>
                       <input type="text" value={config.hero.location} onChange={(e) => handleConfigChange('hero', 'location', e.target.value)} className="w-full p-2 border rounded" />
                     </div>
                     <div className="md:col-span-2">
                       <label className="block text-sm font-medium mb-1">কাউন্টডাউন তারিখ (ISO Format: YYYY-MM-DDTHH:MM:SS)</label>
                       <input type="datetime-local" value={config.countdownDate} onChange={(e) => handleConfigChange('countdownDate', '', e.target.value)} className="w-full p-2 border rounded" />
                     </div>
                     <div className="md:col-span-2">
                       <label className="block text-sm font-medium mb-1">কভার ছবি</label>
                       <div className="flex items-center gap-4">
                          <img src={config.hero.image} alt="Cover" className="h-20 w-32 object-cover rounded border" />
                          <input type="file" accept="image/*" onChange={(e) => handleImageUpload(e, 'hero')} className="text-sm" />
                       </div>
                     </div>
                   </div>
                </section>

                {/* Contact Section */}
                <section className="border p-4 rounded-lg bg-gray-50">
                  <h3 className="text-lg font-bold mb-4 border-b pb-2">যোগাযোগ তথ্য</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium mb-1">ফোন</label>
                      <input type="text" value={config.contact.phone} onChange={(e) => handleConfigChange('contact', 'phone', e.target.value)} className="w-full p-2 border rounded" />
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-1">ইমেইল</label>
                      <input type="text" value={config.contact.email} onChange={(e) => handleConfigChange('contact', 'email', e.target.value)} className="w-full p-2 border rounded" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-sm font-medium mb-1">ঠিকানা</label>
                      <input type="text" value={config.contact.address} onChange={(e) => handleConfigChange('contact', 'address', e.target.value)} className="w-full p-2 border rounded" />
                    </div>

                    {/* Google Maps Coordinates */}
                    <div>
                      <label className="block text-sm font-medium mb-1">Latitude (অক্ষাংশ)</label>
                      <input type="text" value={config.contact.latitude || ''} onChange={(e) => handleConfigChange('contact', 'latitude', e.target.value)} className="w-full p-2 border rounded" placeholder="e.g. 23.8103" />
                    </div>
                    <div>
                      <label className="block text-sm font-medium mb-1">Longitude (দ্রাঘিমাংশ)</label>
                      <input type="text" value={config.contact.longitude || ''} onChange={(e) => handleConfigChange('contact', 'longitude', e.target.value)} className="w-full p-2 border rounded" placeholder="e.g. 90.4125" />
                    </div>

                     <div className="md:col-span-2">
                      <label className="block text-sm font-medium mb-1">গুগল ম্যাপ URL (Embed Link - Optional)</label>
                      <input type="text" value={config.contact.mapUrl} onChange={(e) => handleConfigChange('contact', 'mapUrl', e.target.value)} className="w-full p-2 border rounded" />
                    </div>
                  </div>
                </section>

                {/* Gallery */}
                <section className="border p-4 rounded-lg bg-gray-50">
                  <h3 className="text-lg font-bold mb-4 border-b pb-2">গ্যালারি</h3>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                    {config.gallery.map((img, idx) => (
                      <div key={idx} className="relative group">
                        <img src={img} alt="gallery" className="w-full h-32 object-cover rounded" />
                        <button 
                          onClick={() => removeGalleryImage(idx)}
                          className="absolute top-1 right-1 bg-red-500 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                    ))}
                  </div>
                  <div className="flex items-center gap-2 border-2 border-dashed border-gray-300 p-4 rounded-lg justify-center cursor-pointer hover:bg-gray-100 transition-colors">
                    <label className="cursor-pointer flex flex-col items-center">
                      <Upload className="text-gray-500 mb-2" />
                      <span className="text-sm font-medium text-gray-600">নতুন ছবি আপলোড করুন</span>
                      <input type="file" accept="image/*" className="hidden" onChange={(e) => handleImageUpload(e, 'gallery')} />
                    </label>
                  </div>
                </section>

                {/* Stories Editor - Simplified for demo */}
                <section className="border p-4 rounded-lg bg-gray-50">
                  <h3 className="text-lg font-bold mb-4 border-b pb-2">গল্প (Stories)</h3>
                  {config.stories.map((story, index) => (
                    <div key={index} className="mb-6 p-4 bg-white rounded border">
                      <h4 className="font-bold mb-2">Story #{index + 1}</h4>
                      <div className="grid grid-cols-1 gap-2">
                         <input type="text" value={story.year} onChange={(e) => handleConfigChange('stories', 'year', e.target.value, index)} className="w-full p-2 border rounded" placeholder="Year" />
                         <input type="text" value={story.title} onChange={(e) => handleConfigChange('stories', 'title', e.target.value, index)} className="w-full p-2 border rounded" placeholder="Title" />
                         <textarea value={story.description} onChange={(e) => handleConfigChange('stories', 'description', e.target.value, index)} className="w-full p-2 border rounded" placeholder="Description" rows={3} />
                          <div className="flex items-center gap-4 mt-2">
                            <img src={story.image} alt="Story" className="h-16 w-16 object-cover rounded border" />
                            <input type="file" accept="image/*" onChange={(e) => handleImageUpload(e, 'stories', index)} className="text-sm" />
                         </div>
                      </div>
                    </div>
                  ))}
                </section>

              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import { Mail, Phone, MapPin, Send, Loader2, Navigation } from 'lucide-react';
import { saveMessage } from '../services/storage';
import { WebsiteConfig } from '../types';

interface ContactProps {
  contact: WebsiteConfig['contact'];
}

const Contact: React.FC<ContactProps> = ({ contact }) => {
  const [formData, setFormData] = useState({ name: '', email: '', message: '' });
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('loading');
    const success = await saveMessage(formData);
    if (success) {
      setStatus('success');
      setFormData({ name: '', email: '', message: '' });
      setTimeout(() => setStatus('idle'), 3000);
    } else {
      setStatus('error');
    }
  };

  const getMapLink = () => {
    if (contact.latitude && contact.longitude) {
      return `https://www.google.com/maps/dir/?api=1&destination=${contact.latitude},${contact.longitude}`;
    }
    return null;
  };

  return (
    <section id="contact" className="py-20 bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">

          {/* Contact Info & Form */}
          <div>
            <h2 className="text-4xl font-cursive text-wedding-primary mb-6">যোগাযোগ</h2>
            <p className="text-gray-600 mb-8">যে কোন প্রয়োজনে আমাদের সাথে যোগাযোগ করতে পারেন।</p>

            <div className="space-y-6 mb-10">
              <div className="flex items-start">
                <div className="bg-white p-3 rounded-full shadow-sm mr-4">
                  <Phone className="text-wedding-primary" size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-gray-800">ফোন</h4>
                  <p className="text-gray-600">{contact.phone}</p>
                </div>
              </div>
              <div className="flex items-start">
                <div className="bg-white p-3 rounded-full shadow-sm mr-4">
                  <Mail className="text-wedding-primary" size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-gray-800">ইমেইল</h4>
                  <p className="text-gray-600">{contact.email}</p>
                </div>
              </div>
              <div className="flex items-start">
                <div className="bg-white p-3 rounded-full shadow-sm mr-4">
                  <MapPin className="text-wedding-primary" size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-gray-800">ঠিকানা</h4>
                  <p className="text-gray-600">{contact.address}</p>
                </div>
              </div>
            </div>

            <form onSubmit={handleSubmit} className="bg-white p-6 rounded-xl shadow-sm">
              <h4 className="text-lg font-bold mb-4 text-gray-800">বার্তা পাঠান</h4>
              <div className="space-y-4">
                <input
                  type="text"
                  placeholder="আপনার নাম"
                  required
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-wedding-primary"
                />
                <input
                  type="email"
                  placeholder="ইমেইল"
                  required
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-wedding-primary"
                />
                <textarea
                  rows={3}
                  placeholder="আপনার বার্তা..."
                  required
                  value={formData.message}
                  onChange={e => setFormData({...formData, message: e.target.value})}
                  className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-wedding-primary"
                ></textarea>
                <button 
                  type="submit"
                  disabled={status === 'loading' || status === 'success'}
                  className={`w-full py-2 px-4 rounded-lg text-white font-medium transition-colors flex items-center justify-center gap-2 ${status === 'success' ? 'bg-green-500' : 'bg-wedding-primary hover:bg-wedding-secondary'}`}
                >
                  {status === 'loading' ? <Loader2 className="animate-spin" size={18} /> : 
                   status === 'success' ? 'পাঠানো হয়েছে' : 
                   <>পাঠান <Send size={18} /></>}
                </button>
              </div>
            </form>
          </div>

          {/* Map */}
          <div className="flex flex-col h-full min-h-[400px]">
            <div className="flex-grow bg-gray-200 rounded-xl overflow-hidden shadow-lg border-4 border-white mb-4 relative">
              <iframe 
                src={contact.mapUrl} 
                width="100%" 
                height="100%" 
                style={{ border: 0, position: 'absolute', top: 0, left: 0 }} 
                allowFullScreen={true} 
                loading="lazy"
                title="Wedding Location"
              ></iframe>
            </div>

            {getMapLink() && (
              <a 
                href={getMapLink()!}
                target="_blank" 
                rel="noopener noreferrer"
                className="bg-blue-600 hover:bg-blue-700 text-white py-3 px-6 rounded-lg shadow-md transition-colors flex items-center justify-center gap-2 font-semibold"
              >
                <Navigation size={20} /> গুগল ম্যাপে দেখুন (Get Directions)
              </a>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Contact;

