import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import cors from 'cors';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = process.env.PORT || 5000;

// 1. Ensure /image folder exists
const uploadDir = path.join(__dirname, 'image');
if (!fs.existsSync(uploadDir)) {
    fs.mkdirSync(uploadDir, { recursive: true });
}

// 2. Configure CORS
app.use(cors());
app.use(express.json());

// 7. Make /image folder publicly accessible
app.use("/image", express.static(path.join(__dirname, "image")));

// 3. Multer Configuration
const storage = multer.diskStorage({
    destination: (req, file, cb) => {
        cb(null, 'image/');
    },
    filename: (req, file, cb) => {
        // Generate unique name: timestamp + random string + original extension
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        const ext = path.extname(file.originalname).toLowerCase();
        cb(null, `wedding-${uniqueSuffix}${ext}`);
    }
});

const fileFilter = (req, file, cb) => {
    // Restrict file types
    const allowedTypes = /jpeg|jpg|png|webp/;
    const mimetype = allowedTypes.test(file.mimetype);
    const extname = allowedTypes.test(path.extname(file.originalname).toLowerCase());

    if (mimetype && extname) {
        return cb(null, true);
    }
    cb(new Error("শুধুমাত্র jpg, jpeg, png এবং webp ফাইল আপলোড করা যাবে।"));
};

const upload = multer({
    storage: storage,
    limits: { fileSize: 5 * 1024 * 1024 }, // 5MB limit
    fileFilter: fileFilter
});

// 5. API Endpoint for Upload
app.post('/api/upload', (req, res) => {
    const uploadSingle = upload.single('image');

    uploadSingle(req, res, (err) => {
        if (err instanceof multer.MulterError) {
            // A Multer error occurred when uploading.
            if (err.code === 'LIMIT_FILE_SIZE') {
                return res.status(400).json({ success: false, message: "ফাইলটি ৫ এমবি এর বেশি বড় হতে পারবে না।" });
            }
            return res.status(400).json({ success: false, message: err.message });
        } else if (err) {
            // An unknown error occurred when uploading.
            return res.status(400).json({ success: false, message: err.message });
        }

        if (!req.file) {
            return res.status(400).json({ success: false, message: "কোন ছবি সিলেক্ট করা হয়নি।" });
        }

        // Success response
        res.json({
            success: true,
            imageUrl: `/image/${req.file.filename}`
        });
    });
});

app.listen(PORT, () => {
    console.log(`Server is running on http://localhost:${PORT}`);
    console.log(`Static images available at http://localhost:${PORT}/image`);
});

/**
 * API Service for backend communication
 */

const API_BASE_URL = 'http://localhost:5000';

export interface UploadResponse {
  success: boolean;
  imageUrl?: string;
  message?: string;
}

/**
 * Upload an image to the backend server with progress tracking
 */
export const uploadImage = (
  file: File,
  onProgress: (percent: number) => void
): Promise<UploadResponse> => {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    const formData = new FormData();
    formData.append('image', file);

    xhr.upload.addEventListener('progress', (event) => {
      if (event.lengthComputable) {
        const percent = Math.round((event.loaded / event.total) * 100);
        onProgress(percent);
      }
    });

    xhr.addEventListener('load', () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        try {
          const response = JSON.parse(xhr.responseText);
          // Prepend base URL to image URL for local dev if needed
          // though usually /image/path is enough if proxied or served from same origin
          resolve(response);
        } catch (e) {
          reject(new Error("Invalid server response"));
        }
      } else {
        try {
          const response = JSON.parse(xhr.responseText);
          reject(new Error(response.message || "Upload failed"));
        } catch (e) {
          reject(new Error("Server error"));
        }
      }
    });

    xhr.addEventListener('error', () => {
      reject(new Error("Network error"));
    });

    xhr.open('POST', `${API_BASE_URL}/api/upload`);
    xhr.send(formData);
  });
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getRSVPs, getMessages, getWebsiteConfig, saveWebsiteConfig } from '../services/storage';
import { uploadImage } from '../services/api';
import { Guest, ContactMessage, WebsiteConfig, EventItem } from '../types';
import { Users, MessageSquare, LogOut, Edit, Save, Trash2, Plus, Upload, Loader2 } from 'lucide-react';

const AdminDashboard: React.FC = () => {
  const [rsvps, setRsvps] = useState<Guest[]>([]);
  const [messages, setMessages] = useState<ContactMessage[]>([]);
  const [config, setConfig] = useState<WebsiteConfig | null>(null);
  const [activeTab, setActiveTab] = useState<'rsvp' | 'messages' | 'content'>('rsvp');
  const [saving, setSaving] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<{ [key: string]: number }>({});
  const navigate = useNavigate();

  useEffect(() => {
    const isAdmin = localStorage.getItem('isAdmin');
    if (!isAdmin) {
      navigate('/admin');
      return;
    }

    const fetchData = async () => {
      const rsvpData = await getRSVPs();
      const msgData = await getMessages();
      const configData = await getWebsiteConfig();
      setRsvps(rsvpData);
      setMessages(msgData);
      setConfig(configData);
    };
    fetchData();
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('isAdmin');
    navigate('/admin');
  };

  const handleConfigChange = (section: keyof WebsiteConfig, field: string, value: any, index?: number) => {
    if (!config) return;

    setConfig(prev => {
      if (!prev) return null;
      const newConfig = { ...prev };

      if (section === 'stories' && typeof index === 'number') {
        newConfig.stories = [...prev.stories];
        newConfig.stories[index] = { ...newConfig.stories[index], [field]: value };
      } else if (section === 'events' && typeof index === 'number') {
        newConfig.events = [...prev.events];
        newConfig.events[index] = { ...newConfig.events[index], [field]: value };
      } else if (section === 'hero') {
        newConfig.hero = { ...prev.hero, [field]: value };
      } else if (section === 'contact') {
        newConfig.contact = { ...prev.contact, [field]: value };
      } else if (section === 'countdownDate') {
         newConfig.countdownDate = value;
      }
      return newConfig;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, section: string, index?: number) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const key = `${section}-${index ?? 'main'}`;
    setUploadProgress(prev => ({ ...prev, [key]: 0 }));

    try {
      const response = await uploadImage(file, (percent) => {
        setUploadProgress(prev => ({ ...prev, [key]: percent }));
      });

      if (response.success && response.imageUrl) {
        // Construct full URL if needed, but path is usually fine if server serves frontend
        const fullUrl = `http://localhost:5000${response.imageUrl}`;

        if (section === 'gallery') {
           setConfig(prev => {
               if(!prev) return null;
               return { ...prev, gallery: [...prev.gallery, fullUrl] }
           });
        } else if (section === 'hero') {
           handleConfigChange('hero', 'image', fullUrl);
        } else if (section === 'stories' && typeof index === 'number') {
           handleConfigChange('stories', 'image', fullUrl, index);
        }
      } else {
        alert(response.message || "আপলোড ব্যর্থ হয়েছে।");
      }
    } catch (error: any) {
      console.error("Upload error", error);
      alert(error.message || "সার্ভারের সাথে যোগাযোগ করতে সমস্যা হচ্ছে। নিশ্চিত করুন যে ব্যাকএন্ড সার্ভার চালু আছে।");
    } finally {
      setTimeout(() => {
        setUploadProgress(prev => {
          const next = { ...prev };
          delete next[key];
          return next;
        });
      }, 1000);
    }
  };

  const removeGalleryImage = (index: number) => {
    setConfig(prev => {
        if(!prev) return null;
        const newGallery = prev.gallery.filter((_, i) => i !== index);
        return { ...prev, gallery: newGallery };
    });
  };

