import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import cors from 'cors';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = process.env.PORT || 5000;

// 1. Ensure /image folder exists automatically
const uploadDir = path.join(__dirname, 'image');
if (!fs.existsSync(uploadDir)) {
    fs.mkdirSync(uploadDir, { recursive: true });
}

// 2. Configure CORS and JSON parsing
app.use(cors());
app.use(express.json());

// 7. Make /image folder publicly accessible
app.use("/image", express.static(path.join(__dirname, "image")));

// 3. Multer Configuration for Unique Filenames and Security
const storage = multer.diskStorage({
    destination: (req, file, cb) => {
        cb(null, 'image/');
    },
    filename: (req, file, cb) => {
        // Generate unique name: timestamp + random string + original extension
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        const ext = path.extname(file.originalname).toLowerCase();
        cb(null, `upload-${uniqueSuffix}${ext}`);
    }
});

const fileFilter = (req, file, cb) => {
    // Restrict file types to mkv, mp4, jpg, jpeg, png, webp
    const allowedExtensions = /mkv|mp4|jpeg|jpg|png|webp/;
    const allowedMimeTypes = /video\/x-matroska|video\/mp4|image\/jpeg|image\/jpg|image\/png|image\/webp/;

    const mimetype = allowedMimeTypes.test(file.mimetype);
    const extname = allowedExtensions.test(path.extname(file.originalname).toLowerCase());

    if (mimetype && extname) {
        return cb(null, true);
    }
    cb(new Error("শুধুমাত্র mkv, mp4, jpg, jpeg, png এবং webp ফাইল আপলোড করা যাবে।"));
};

const upload = multer({
    storage: storage,
    limits: { fileSize: 10 * 1024 * 1024 }, // 10MB limit
    fileFilter: fileFilter
});

// 5. API Endpoint for Secure Upload
app.post('/api/upload', (req, res) => {
    const uploadSingle = upload.single('image');

    uploadSingle(req, res, (err) => {
        if (err instanceof multer.MulterError) {
            if (err.code === 'LIMIT_FILE_SIZE') {
                return res.status(400).json({ success: false, message: "ফাইলটি ১০ এমবি এর বেশি বড় হতে পারবে না।" });
            }
            return res.status(400).json({ success: false, message: `Multer error: ${err.message}` });
        } else if (err) {
            return res.status(400).json({ success: false, message: err.message });
        }

        if (!req.file) {
            return res.status(400).json({ success: false, message: "কোন ফাইল সিলেক্ট করা হয়নি।" });
        }

        // 6. Return response with file path
        res.json({
            success: true,
            imageUrl: `/image/${req.file.filename}`
        });
    });
});

app.listen(PORT, () => {
    console.log(`Server is running on http://localhost:${PORT}`);
    console.log(`Static assets available at http://localhost:${PORT}/image`);
});

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getRSVPs, getMessages, getWebsiteConfig, saveWebsiteConfig } from '../services/storage';
