      <div className="w-4/5 h-1 bg-gray-700 mt-2 rounded-full overflow-hidden">
        <div className="h-full bg-green-500 transition-all duration-300" style={{ width: `${percent}%` }}></div>
      </div>
    </div>
  );

  const isVideo = (url: string) => url.toLowerCase().match(/\.(mp4|mkv)$/);

  if (!config) return <div className="p-10 text-center">Loading...</div>;

  return (
    <div className="min-h-screen bg-gray-50 font-bengali">
      {/* Top Bar */}
      <header className="bg-white shadow sticky top-0 z-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex justify-between items-center">
          <h1 className="text-xl md:text-2xl font-bold text-gray-800">অ্যাডমিন ড্যাশবোর্ড</h1>
          <button 
            onClick={handleLogout}
            className="flex items-center gap-2 text-red-600 hover:text-red-700 font-medium"
          >
            <LogOut size={18} /> লগআউট
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-wedding-primary flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">মোট RSVP</p>
              <h3 className="text-3xl font-bold text-gray-800">{rsvps.length}</h3>
              <p className="text-sm text-gray-600 mt-1">মোট অতিথি: {totalGuests} জন</p>
            </div>
            <div className="p-4 bg-wedding-bg rounded-full text-wedding-primary">
              <Users size={24} />
            </div>
          </div>
          <div className="bg-white p-6 rounded-xl shadow-sm border-l-4 border-blue-500 flex items-center justify-between">
            <div>
              <p className="text-gray-500 text-sm">নতুন বার্তা</p>
              <h3 className="text-3xl font-bold text-gray-800">{messages.length}</h3>
            </div>
            <div className="p-4 bg-blue-50 rounded-full text-blue-500">
              <MessageSquare size={24} />
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="bg-white rounded-xl shadow-sm overflow-hidden min-h-[500px]">
          <div className="border-b border-gray-200">
            <nav className="flex -mb-px overflow-x-auto">
