export const getWebsiteConfig = async (): Promise<WebsiteConfig> => {
  await delay(200);
  const stored = await dbGet(CONFIG_KEY);

  if (!stored) {
    // If not in DB, try localStorage (migration path) or use defaults
    const local = localStorage.getItem(CONFIG_KEY);
    if (local) {
       try {
         const parsed = JSON.parse(local);
         await dbSet(CONFIG_KEY, parsed); // Migrate to DB
         return parsed;
       } catch (e) {
         console.error("Error parsing localStorage config", e);
       }
    }

    // Save defaults to DB
    await dbSet(CONFIG_KEY, DEFAULT_CONFIG);
    return DEFAULT_CONFIG;
  }
  return stored;
};

export const saveWebsiteConfig = async (config: WebsiteConfig): Promise<boolean> => {
  await delay(800);
  try {
    await dbSet(CONFIG_KEY, config);
    return true;
  } catch (error) {
    console.error("Error saving config", error);
    return false;
  }
};

