import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import cors from 'cors';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = 5000;
const DB_PATH = path.join(__dirname, 'database.json');
const UPLOAD_DIR = path.join(__dirname, 'image');

// Ensure DB and Upload folder exist
if (!fs.existsSync(UPLOAD_DIR)) fs.mkdirSync(UPLOAD_DIR);
if (!fs.existsSync(DB_PATH)) {
    const initialDB = {
        users: [{ id: 'admin-1', username: '11', password: '00', role: 'superadmin' }],
        rsvps: [],
        messages: [],
        config: null
    };
    fs.writeFileSync(DB_PATH, JSON.stringify(initialDB, null, 2));
}

app.use(cors());
app.use(express.json());
app.use("/image", express.static(UPLOAD_DIR));

// Helper: Read/Write DB
const readDB = () => JSON.parse(fs.readFileSync(DB_PATH, 'utf-8'));
const writeDB = (data) => fs.writeFileSync(DB_PATH, JSON.stringify(data, null, 2));

// Simple Mock JWT & Security Middleware
const verifyToken = (req, res, next) => {
    const token = req.headers['authorization'];
    if (!token) return res.status(401).json({ message: 'Unauthorized' });
    // In this mock environment, we just check if the token matches our static string
    if (token === 'mock-jwt-token') {
        req.user = { role: 'superadmin' };
        next();
    } else {
        res.status(403).json({ message: 'Invalid Token' });
    }
};

// --- AUTH ROUTES ---
app.post('/api/admin/login', (req, res) => {
    const { username, password } = req.body;

    // Explicitly check for 11/00 to ensure user can always log in
    if (username === '11' && password === '00') {
        return res.json({ token: 'mock-jwt-token', user: { username: 'admin', role: 'superadmin' } });
    }

    const db = readDB();
    const user = db.users.find(u => u.username === username && u.password === password);
    if (user) {
        res.json({ token: 'mock-jwt-token', user: { username: user.username, role: user.role } });
    } else {
        res.status(401).json({ message: 'Invalid credentials' });
    }
});

// --- ADMIN API ROUTES ---

// 1. Stats
app.get('/api/admin/stats', verifyToken, (req, res) => {
    const db = readDB();
    const stats = {
        totalRSVPs: db.rsvps.length,
        totalGuests: db.rsvps.reduce((acc, curr) => acc + (curr.guestsCount || 0), 0),
        totalMessages: db.messages.length,
        trafficData: [
            { name: 'Mon', visits: 400 }, { name: 'Tue', visits: 300 },
            { name: 'Wed', visits: 600 }, { name: 'Thu', visits: 800 },
            { name: 'Fri', visits: 500 }, { name: 'Sat', visits: 900 },
            { name: 'Sun', visits: 1000 }
        ]
    };
    res.json(stats);
});

// 2. RSVP Management
app.get('/api/admin/rsvps', verifyToken, (req, res) => {
    res.json(readDB().rsvps);
});

app.delete('/api/admin/rsvps/:id', verifyToken, (req, res) => {
    const db = readDB();
    db.rsvps = db.rsvps.filter(r => r.id !== req.params.id);
    writeDB(db);
    res.json({ success: true });
});

// 3. User Feedback from Frontend (Public)
app.post('/api/public/rsvp', (req, res) => {
    const db = readDB();
    const newRSVP = { ...req.body, id: Date.now().toString(), createdAt: new Date() };
    db.rsvps.push(newRSVP);
    writeDB(db);
    res.json({ success: true });
});

// 4. File Upload (Multer)
const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, 'image/'),
    filename: (req, file, cb) => {
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
    }
});
const upload = multer({ storage, limits: { fileSize: 10 * 1024 * 1024 } });

app.post('/api/upload', verifyToken, upload.single('image'), (req, res) => {
    if (!req.file) return res.status(400).send('No file uploaded.');
    res.json({ success: true, imageUrl: `/image/${req.file.filename}` });
});

app.listen(PORT, '127.0.0.1', () => {
    console.log(`🚀 Production Admin Server: http://127.0.0.1:${PORT}`);
});

/**
 * API Service for backend communication
 */

export interface UploadResponse {
  success: boolean;
  imageUrl?: string;
  message?: string;
}

/**
 * Upload an image to the backend server with progress tracking.
 * Uses relative paths to leverage the Vite proxy (dev) or same-origin (prod).
 */
export const uploadImage = (
  file: File,
  onProgress: (percent: number) => void
): Promise<UploadResponse> => {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    const formData = new FormData();
    formData.append('image', file);

    xhr.upload.addEventListener('progress', (event) => {
      if (event.lengthComputable) {
        const percent = Math.round((event.loaded / event.total) * 100);
        onProgress(percent);
      }
    });

    xhr.addEventListener('load', () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        try {
          const response = JSON.parse(xhr.responseText);
          resolve(response);
        } catch (e) {
          reject(new Error("সার্ভার থেকে সঠিক রেসপন্স পাওয়া যায়নি।"));
        }
      } else {
        try {
          const response = JSON.parse(xhr.responseText);
          reject(new Error(response.message || "আপলোড ব্যর্থ হয়েছে।"));
        } catch (e) {
          reject(new Error(`সার্ভার এরর: ${xhr.status}`));
        }
      }
    });

    xhr.addEventListener('error', () => {
      reject(new Error("নেটওয়ার্ক এরর! অনুগ্রহ করে নিশ্চিত করুন যে ব্যাকএন্ড সার্ভার চালু আছে।"));
    });

    // Using relative path to work with Vite proxy
    xhr.open('POST', '/api/upload');

    // Add Authorization header for the backend verifyToken middleware
    const token = localStorage.getItem('admin_token');
    if (token) {
      xhr.setRequestHeader('Authorization', token);
    }

    xhr.send(formData);
  });
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getRSVPs, getMessages, getWebsiteConfig, saveWebsiteConfig } from '../services/storage';
import { uploadImage } from '../services/api';
import { adminApi } from '../services/adminApi';
import { Guest, ContactMessage, WebsiteConfig, EventItem } from '../types';
import { Users, MessageSquare, LogOut, Edit, Save, Trash2, Plus, Upload, Loader2, Video as VideoIcon, Play } from 'lucide-react';

const AdminDashboard: React.FC = () => {
  const [rsvps, setRsvps] = useState<Guest[]>([]);
  const [messages, setMessages] = useState<ContactMessage[]>([]);
  const [config, setConfig] = useState<WebsiteConfig | null>(null);
  const [activeTab, setActiveTab] = useState<'rsvp' | 'messages' | 'content'>('rsvp');
  const [saving, setSaving] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<{ [key: string]: number }>({});
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem('admin_token');
    if (!token) {
      navigate('/admin');
      return;
    }

    const fetchData = async () => {
      try {
        const configData = await getWebsiteConfig();
        setConfig(configData);

        // Fetch real-time rsvps and messages from backend if needed
        const liveRSVPs = await adminApi.getRSVPs();
        setRsvps(liveRSVPs);

        const localMessages = await getMessages();
        setMessages(localMessages);
      } catch (err) {
        console.error("Dashboard data fetch error", err);
      }
    };
    fetchData();
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('admin_token');
    navigate('/admin');
  };

  const handleConfigChange = (section: keyof WebsiteConfig, field: string, value: any, index?: number) => {
    if (!config) return;

    setConfig(prev => {
      if (!prev) return null;
      const newConfig = { ...prev };

      if (section === 'stories' && typeof index === 'number') {
        newConfig.stories = [...prev.stories];
        newConfig.stories[index] = { ...newConfig.stories[index], [field]: value };
      } else if (section === 'events' && typeof index === 'number') {
        newConfig.events = [...prev.events];
        newConfig.events[index] = { ...newConfig.events[index], [field]: value };
      } else if (section === 'hero') {
        newConfig.hero = { ...prev.hero, [field]: value };
      } else if (section === 'contact') {
        newConfig.contact = { ...prev.contact, [field]: value };
      } else if (section === 'countdownDate') {
         newConfig.countdownDate = value;
      }
      return newConfig;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, section: string, index?: number) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const key = `${section}-${index ?? 'main'}`;
    setUploadProgress(prev => ({ ...prev, [key]: 0 }));

    try {
      const response = await uploadImage(file, (percent) => {
        setUploadProgress(prev => ({ ...prev, [key]: percent }));
      });

      if (response.success && response.imageUrl) {
        const finalUrl = response.imageUrl; 

        if (section === 'gallery') {
           setConfig(prev => {
               if(!prev) return null;
               return { ...prev, gallery: [...prev.gallery, finalUrl] }
           });
        } else if (section === 'hero') {
           handleConfigChange('hero', 'image', finalUrl);
        } else if (section === 'stories' && typeof index === 'number') {
           handleConfigChange('stories', 'image', finalUrl, index);
        }
      } else {
        alert(response.message || "আপলোড ব্যর্থ হয়েছে।");
      }
    } catch (error: any) {
      console.error("Upload error", error);
      alert(error.message || "সার্ভারের সাথে যোগাযোগ করতে সমস্যা হচ্ছে।");
    } finally {
      setTimeout(() => {
        setUploadProgress(prev => {
          const next = { ...prev };
          delete next[key];
          return next;
        });
      }, 1000);
    }
  };

  const removeGalleryImage = (index: number) => {
    setConfig(prev => {
        if(!prev) return null;
        const newGallery = prev.gallery.filter((_, i) => i !== index);
        return { ...prev, gallery: newGallery };
    });
  };

  const saveContent = async () => {
    if (!config) return;
    setSaving(true);
    const success = await saveWebsiteConfig(config);
    setSaving(false);

    if (success) {
      alert('পরিবর্তন সংরক্ষণ করা হয়েছে!');
    } else {
      alert('সংরক্ষণ ব্যর্থ হয়েছে!');
    }
  };

  const totalGuests = rsvps.reduce((acc, curr) => acc + (curr.guestsCount || 0), 0);

  const ProgressOverlay = ({ percent }: { percent: number }) => (
