            <div>
              <p className="text-gray-500 text-sm">নতুন বার্তা</p>
              <h3 className="text-3xl font-bold text-gray-800">{messages.length}</h3>
            </div>
            <div className="p-4 bg-blue-50 rounded-full text-blue-500">
              <MessageSquare size={24} />
            </div>
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm overflow-hidden min-h-[500px]">
          <div className="border-b border-gray-200">
            <nav className="flex -mb-px overflow-x-auto">
              <button onClick={() => setActiveTab('rsvp')} className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'rsvp' ? 'border-wedding-primary text-wedding-primary' : 'border-transparent text-gray-500 hover:text-gray-700'}`}>
                <Users size={16} /> RSVP তালিকা
              </button>
              <button onClick={() => setActiveTab('messages')} className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'messages' ? 'border-blue-500 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}>
                <MessageSquare size={16} /> বার্তাসমূহ
              </button>
              <button onClick={() => setActiveTab('content')} className={`py-4 px-6 font-medium text-sm flex items-center gap-2 border-b-2 transition-colors whitespace-nowrap ${activeTab === 'content' ? 'border-green-500 text-green-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}>
                <Edit size={16} /> ওয়েবসাইট এডিট
