            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-rose-500 hover:bg-rose-600 text-white py-3.5 rounded-xl transition-all font-bold shadow-lg shadow-rose-500/20 flex items-center justify-center gap-2 disabled:bg-rose-400"
          >
            {loading ? (
              <>
                <Loader2 className="animate-spin" size={20} />
                <span>Logging in...</span>
              </>
            ) : (
              'Login to Dashboard'
            )}
          </button>
        </form>

        <div className="mt-8 text-center">
          <button 
            disabled={loading}
            onClick={() => navigate('/')} 
            className="text-slate-400 hover:text-rose-500 text-sm font-medium transition-colors disabled:opacity-50"
          >
            Back to Website
          </button>
        </div>
      </div>
    </div>
  );
};

export default AdminLogin;

/**
 * Production-ready API service for Admin Dashboard
 */

const BASE_URL = '/api';

const getHeaders = () => {
    const token = localStorage.getItem('admin_token');
    return {
        'Content-Type': 'application/json',
        'Authorization': token || ''
    };
};

export const adminApi = {
    login: async (credentials: any) => {
        try {
            const res = await fetch(`${BASE_URL}/admin/login`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(credentials)
            });

            if (!res.ok) {
                // Try to get error message from server
                const errorData = await res.json().catch(() => ({}));
                if (res.status === 401) {
                    throw new Error('Authentication failed');
                }
                throw new Error(errorData.message || `Server error: ${res.status}`);
            }

            const data = await res.json();
            localStorage.setItem('admin_token', data.token);
            return data;
        } catch (error) {
            throw error;
        }
    },

    getStats: async () => {
        try {
            const res = await fetch(`${BASE_URL}/admin/stats`, { headers: getHeaders() });
            if (res.status === 401) {
                // Return fallback structure if unauthorized, components should handle redirect
                return { totalRSVPs: 0, totalGuests: 0, totalMessages: 0, trafficData: [] };
            }
            if (!res.ok) throw new Error("Failed to fetch");
            return res.json();
        } catch (e) {
            console.error(e);
            throw e;
        }
    },

    getRSVPs: async () => {
        const res = await fetch(`${BASE_URL}/admin/rsvps`, { headers: getHeaders() });
        return res.json();
    },

    deleteRSVP: async (id: string) => {
        const res = await fetch(`${BASE_URL}/admin/rsvps/${id}`, {
            method: 'DELETE',
            headers: getHeaders()
        });
        return res.json();
    },

    uploadFile: async (file: File, onProgress?: (p: number) => void) => {
        return new Promise((resolve, reject) => {
            const xhr = new XMLHttpRequest();
            const formData = new FormData();
            formData.append('image', file);

            xhr.upload.addEventListener('progress', (e) => {
                if (e.lengthComputable && onProgress) {
                    onProgress(Math.round((e.loaded / e.total) * 100));
                }
            });

            xhr.onload = () => {
                if (xhr.status === 200) resolve(JSON.parse(xhr.responseText));
                else reject(new Error('Upload failed'));
            };

            xhr.open('POST', `${BASE_URL}/upload`);
            xhr.setRequestHeader('Authorization', localStorage.getItem('admin_token') || '');
            xhr.send(formData);
        });
    }
};

