    if (!config) return;

    setConfig(prev => {
      if (!prev) return null;
      const newConfig = { ...prev };

      if (section === 'stories' && typeof index === 'number') {
        newConfig.stories = [...prev.stories];
        newConfig.stories[index] = { ...newConfig.stories[index], [field]: value };
      } else if (section === 'events' && typeof index === 'number') {
        newConfig.events = [...prev.events];
        newConfig.events[index] = { ...newConfig.events[index], [field]: value };
      } else if (section === 'hero') {
        newConfig.hero = { ...prev.hero, [field]: value };
      } else if (section === 'contact') {
        newConfig.contact = { ...prev.contact, [field]: value };
      } else if (section === 'countdownDate') {
         newConfig.countdownDate = value;
      }
      return newConfig;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, section: string, index?: number) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const key = `${section}-${index ?? 'main'}`;
    setUploadProgress(prev => ({ ...prev, [key]: 0 }));

    try {
      const response = await uploadImage(file, (percent) => {
        setUploadProgress(prev => ({ ...prev, [key]: percent }));
      });

      if (response.success && response.imageUrl) {
        const finalUrl = response.imageUrl; 

        if (section === 'gallery') {
           setConfig(prev => {
               if(!prev) return null;
               return { ...prev, gallery: [...prev.gallery, finalUrl] }
           });
        } else if (section === 'hero') {
           handleConfigChange('hero', 'image', finalUrl);
        } else if (section === 'stories' && typeof index === 'number') {
           handleConfigChange('stories', 'image', finalUrl, index);
        }
      } else {
        alert(response.message || "আপলোড ব্যর্থ হয়েছে।");
      }
    } catch (error: any) {
      console.error("Upload error", error);
      alert(error.message || "সার্ভারের সাথে যোগাযোগ করতে সমস্যা হচ্ছে।");
    } finally {
      setTimeout(() => {
        setUploadProgress(prev => {
          const next = { ...prev };
          delete next[key];
          return next;
        });
      }, 1000);
    }
  };

  const removeGalleryImage = (index: number) => {
    setConfig(prev => {
        if(!prev) return null;
        const newGallery = prev.gallery.filter((_, i) => i !== index);
        return { ...prev, gallery: newGallery };
    });
  };

  const saveContent = async () => {
