import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import cors from 'cors';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = 5000;
const DB_PATH = path.join(__dirname, 'database.json');
const UPLOAD_DIR = path.join(__dirname, 'image');

// Ensure DB and Upload folder exist
if (!fs.existsSync(UPLOAD_DIR)) fs.mkdirSync(UPLOAD_DIR);
if (!fs.existsSync(DB_PATH)) {
    const initialDB = {
        users: [{ id: 'admin-1', username: 'admin', password: 'admin123', role: 'superadmin' }],
        rsvps: [],
        messages: [],
        config: null
    };
    fs.writeFileSync(DB_PATH, JSON.stringify(initialDB, null, 2));
}

app.use(cors());
app.use(express.json());
app.use("/image", express.static(UPLOAD_DIR));

// Helper: Read/Write DB
const readDB = () => JSON.parse(fs.readFileSync(DB_PATH, 'utf-8'));
const writeDB = (data) => fs.writeFileSync(DB_PATH, JSON.stringify(data, null, 2));

// Simple Mock JWT & Security Middleware
const verifyToken = (req, res, next) => {
    // LOGIN SYSTEM DISABLED: Always allow access
    req.user = { role: 'superadmin' };
    next();
};

// --- AUTH ROUTES ---
app.post('/api/admin/login', (req, res) => {
    // Login route kept for compatibility but technically not needed
    res.json({ token: 'mock-jwt-token', user: { username: 'admin', role: 'superadmin' } });
});

// --- ADMIN API ROUTES ---

// 1. Stats
app.get('/api/admin/stats', verifyToken, (req, res) => {
    const db = readDB();
    const stats = {
        totalRSVPs: db.rsvps.length,
        totalGuests: db.rsvps.reduce((acc, curr) => acc + (curr.guestsCount || 0), 0),
        totalMessages: db.messages.length,
        trafficData: [
            { name: 'Mon', visits: 400 }, { name: 'Tue', visits: 300 },
            { name: 'Wed', visits: 600 }, { name: 'Thu', visits: 800 },
            { name: 'Fri', visits: 500 }, { name: 'Sat', visits: 900 },
            { name: 'Sun', visits: 1000 }
        ]
    };
    res.json(stats);
});

// 2. RSVP Management
app.get('/api/admin/rsvps', verifyToken, (req, res) => {
    res.json(readDB().rsvps);
});

app.delete('/api/admin/rsvps/:id', verifyToken, (req, res) => {
    const db = readDB();
    db.rsvps = db.rsvps.filter(r => r.id !== req.params.id);
    writeDB(db);
    res.json({ success: true });
});

// 3. User Feedback from Frontend (Public)
app.post('/api/public/rsvp', (req, res) => {
    const db = readDB();
    const newRSVP = { ...req.body, id: Date.now().toString(), createdAt: new Date() };
    db.rsvps.push(newRSVP);
    writeDB(db);
    res.json({ success: true });
});

// 4. File Upload (Multer)
const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, 'image/'),
    filename: (req, file, cb) => {
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
    }
});
const upload = multer({ storage, limits: { fileSize: 50 * 1024 * 1024 } }); // Increased limit to 50MB for videos

app.post('/api/upload', verifyToken, upload.single('image'), (req, res) => {
    if (!req.file) return res.status(400).send('No file uploaded.');
    res.json({ success: true, imageUrl: `/image/${req.file.filename}` });
});

// 5. Media Library Routes (New)
app.get('/api/admin/media', verifyToken, (req, res) => {
    fs.readdir(UPLOAD_DIR, (err, files) => {
        if (err) {
            console.error(err);
            return res.status(500).json({ message: 'Failed to scan directory' });
        }

        const media = files.map(file => {
            try {
                const stats = fs.statSync(path.join(UPLOAD_DIR, file));
                return {
                    name: file,
                    url: `/image/${file}`,
                    type: /\.(mp4|mkv|mov|webm)$/i.test(file) ? 'video' : 'image',
                    size: stats.size,
                    createdAt: stats.birthtime
                };
            } catch (e) {
                return null;
            }
        })
        .filter(Boolean) // Remove nulls
        .sort((a, b) => b.createdAt - a.createdAt); // Newest first

        res.json(media);
    });
});

app.delete('/api/admin/media/:filename', verifyToken, (req, res) => {
    const safeFilename = path.basename(req.params.filename); // Security: prevent directory traversal
    const filepath = path.join(UPLOAD_DIR, safeFilename);

    if (fs.existsSync(filepath)) {
        try {
            fs.unlinkSync(filepath);
            res.json({ success: true });
        } catch (e) {
            res.status(500).json({ message: 'Error deleting file' });
        }
    } else {
        res.status(404).json({ message: 'File not found' });
    }
});

app.listen(PORT, '127.0.0.1', () => {
    console.log(`🚀 Production Admin Server: http://127.0.0.1:${PORT}`);
});

/**
 * Production-ready API service for Admin Dashboard
 */

const BASE_URL = '/api';

const getHeaders = () => {
    const token = localStorage.getItem('admin_token');
    return {
        'Content-Type': 'application/json',
        'Authorization': token || ''
    };
};

export const adminApi = {
    login: async (credentials: any) => {
        try {
            const res = await fetch(`${BASE_URL}/admin/login`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(credentials)
            });

            if (!res.ok) {
                // Try to get error message from server
                const errorData = await res.json().catch(() => ({}));
                if (res.status === 401) {
                    throw new Error('Authentication failed');
                }
                throw new Error(errorData.message || `Server error: ${res.status}`);
            }

            const data = await res.json();
            localStorage.setItem('admin_token', data.token);
            return data;
        } catch (error) {
            throw error;
        }
    },

    getStats: async () => {
        try {
            const res = await fetch(`${BASE_URL}/admin/stats`, { headers: getHeaders() });
            if (res.status === 401) {
                // Return fallback structure if unauthorized
                return { totalRSVPs: 0, totalGuests: 0, totalMessages: 0, trafficData: [] };
            }
            if (!res.ok) throw new Error("Failed to fetch");
            return res.json();
        } catch (e) {
            console.error(e);
            throw e;
        }
    },

    getRSVPs: async () => {
        const res = await fetch(`${BASE_URL}/admin/rsvps`, { headers: getHeaders() });
        return res.json();
    },

    deleteRSVP: async (id: string) => {
        const res = await fetch(`${BASE_URL}/admin/rsvps/${id}`, {
            method: 'DELETE',
            headers: getHeaders()
        });
        return res.json();
    },

    getMedia: async () => {
        const res = await fetch(`${BASE_URL}/admin/media`, { headers: getHeaders() });
        if (!res.ok) throw new Error("Failed to fetch media");
        return res.json();
    },

    deleteMedia: async (filename: string) => {
        const res = await fetch(`${BASE_URL}/admin/media/${filename}`, {
            method: 'DELETE',
            headers: getHeaders()
        });
        return res.json();
    },

    uploadFile: async (file: File, onProgress?: (p: number) => void) => {
        return new Promise((resolve, reject) => {
            const xhr = new XMLHttpRequest();
            const formData = new FormData();
            formData.append('image', file);

            xhr.upload.addEventListener('progress', (e) => {
                if (e.lengthComputable && onProgress) {
                    onProgress(Math.round((e.loaded / e.total) * 100));
                }
            });

            xhr.onload = () => {
                if (xhr.status === 200) resolve(JSON.parse(xhr.responseText));
                else reject(new Error('Upload failed'));
            };

            xhr.onerror = () => reject(new Error('Network error'));

            xhr.open('POST', `${BASE_URL}/upload`);
            xhr.setRequestHeader('Authorization', localStorage.getItem('admin_token') || '');
            xhr.send(formData);
        });
    }
};

import React, { useEffect, useState } from 'react';
import { adminApi } from '../services/adminApi';
import { Trash2, Copy, Upload, Film, Image as ImageIcon, Check, Loader2, X, RefreshCw } from 'lucide-react';

interface MediaFile {
    name: string;
    url: string;
    type: 'image' | 'video';
    size: number;
    createdAt: string;
}

const MediaLibrary: React.FC = () => {
    const [media, setMedia] = useState<MediaFile[]>([]);
    const [loading, setLoading] = useState(true);
    const [uploading, setUploading] = useState(false);
    const [progress, setProgress] = useState(0);
    const [copiedId, setCopiedId] = useState<string | null>(null);

    const fetchMedia = async () => {
        try {
            const data = await adminApi.getMedia();
            setMedia(data);
        } catch (error) {
            console.error("Failed to load media", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchMedia();
    }, []);

    const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setUploading(true);
        setProgress(0);

        try {
            await adminApi.uploadFile(file, (p) => setProgress(p));
            await fetchMedia(); // Refresh list
        } catch (error) {
            alert('Upload failed!');
        } finally {
            setUploading(false);
            setProgress(0);
        }
    };

    const handleDelete = async (filename: string) => {
        if (!window.confirm('Are you sure you want to delete this file? This might break pages using this file.')) return;

        try {
            await adminApi.deleteMedia(filename);
            setMedia(prev => prev.filter(m => m.name !== filename));
        } catch (error) {
            alert('Failed to delete file');
        }
    };

    const copyToClipboard = (url: string, name: string) => {
        // Construct full URL if needed, or just keep relative path
        // For admin dashboard ease of use, we usually want the relative path for config
        // or absolute path for external sharing. Let's provide absolute for now.
        const fullUrl = `${window.location.origin}${url}`;
        navigator.clipboard.writeText(fullUrl);
        setCopiedId(name);
        setTimeout(() => setCopiedId(null), 2000);
    };

    const formatSize = (bytes: number) => {
        if (bytes === 0) return '0 B';
        const k = 1024;
        const sizes = ['B', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    };

    if (loading) return (
        <div className="flex h-96 items-center justify-center">
            <Loader2 className="animate-spin text-rose-500" size={48} />
        </div>
    );

    return (
        <div className="space-y-6 animate-fade-in">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">Media Library</h1>
                    <p className="text-slate-500 text-sm mt-1">Manage all your uploaded images and videos</p>
                </div>

                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => { setLoading(true); fetchMedia(); }}
                        className="p-2 text-slate-500 hover:text-slate-700 hover:bg-slate-100 rounded-lg transition-colors"
                        title="Refresh"
                    >
                        <RefreshCw size={20} />
                    </button>
                    <label className={`
                        flex items-center gap-2 px-5 py-2.5 rounded-xl text-white font-medium cursor-pointer transition-all shadow-lg shadow-rose-500/20
                        ${uploading ? 'bg-rose-400 cursor-not-allowed' : 'bg-rose-500 hover:bg-rose-600'}
                    `}>
                        {uploading ? (
                            <>
                                <Loader2 size={18} className="animate-spin" />
                                <span>{progress}%</span>
                            </>
                        ) : (
                            <>
                                <Upload size={18} />
                                <span>Upload New</span>
                            </>
                        )}
                        <input 
                            type="file" 
                            className="hidden" 
                            onChange={handleUpload} 
                            disabled={uploading}
                            accept="image/*,video/*"
                        />
                    </label>
                </div>
            </div>

            {media.length === 0 ? (
                <div className="bg-white rounded-2xl p-12 text-center border-2 border-dashed border-slate-200">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                        <ImageIcon className="text-slate-300" size={32} />
                    </div>
                    <h3 className="text-lg font-medium text-slate-900">No media files yet</h3>
                    <p className="text-slate-500 mt-1 mb-6">Upload your first image or video to get started</p>
                </div>
            ) : (
                <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                    {media.map((file) => (
                        <div key={file.name} className="group bg-white rounded-xl overflow-hidden border border-slate-200 shadow-sm hover:shadow-md transition-all flex flex-col">
                            <div className="relative aspect-square bg-slate-100 overflow-hidden">
                                {file.type === 'video' ? (
                                    <video src={file.url} className="w-full h-full object-cover" />
                                ) : (
                                    <img src={file.url} alt={file.name} className="w-full h-full object-cover" loading="lazy" />
                                )}

                                {/* Overlay */}
                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                                    <button 
                                        onClick={() => copyToClipboard(file.url, file.name)}
                                        className="p-2 bg-white rounded-lg hover:bg-slate-100 text-slate-700 transition-colors"
                                        title="Copy Link"
                                    >
                                        {copiedId === file.name ? <Check size={18} className="text-green-600" /> : <Copy size={18} />}
                                    </button>
                                    <button 
                                        onClick={() => handleDelete(file.name)}
                                        className="p-2 bg-white rounded-lg hover:bg-red-50 text-red-600 transition-colors"
                                        title="Delete"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>

                                {/* Type Badge */}
                                <div className="absolute top-2 left-2 px-2 py-1 bg-black/50 backdrop-blur-md rounded text-xs text-white flex items-center gap-1">
                                    {file.type === 'video' ? <Film size={12} /> : <ImageIcon size={12} />}
                                    <span className="uppercase">{file.name.split('.').pop()}</span>
                                </div>
                            </div>

                            <div className="p-3">
                                <p className="text-sm font-medium text-slate-700 truncate" title={file.name}>{file.name}</p>
                                <p className="text-xs text-slate-400 mt-1">{formatSize(file.size)}</p>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default MediaLibrary;

