/**
 * Production-ready API service for Admin Dashboard
 */

const BASE_URL = '/api';

const getHeaders = () => {
    const token = localStorage.getItem('admin_token');
    return {
        'Content-Type': 'application/json',
        'Authorization': token || ''
    };
};

const handleResponse = async (res: Response) => {
    if (!res.ok) {
        const contentType = res.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
            const errorData = await res.json().catch(() => ({}));
            throw new Error(errorData.message || `Server error: ${res.status}`);
        }
        // If not JSON (e.g. HTML error page from Proxy or 404), throw simple error
        throw new Error(`Request failed with status ${res.status}`);
    }
    // Check if response is empty
    const text = await res.text();
    return text ? JSON.parse(text) : {};
};

export const adminApi = {
    login: async (credentials: any) => {
        try {
            const res = await fetch(`${BASE_URL}/admin/login`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(credentials)
            });

            return await handleResponse(res);
        } catch (error) {
            console.error("Login API error:", error);
            throw error;
        }
    },

    getStats: async () => {
        try {
            const res = await fetch(`${BASE_URL}/admin/stats`, { headers: getHeaders() });
            return await handleResponse(res);
        } catch (e) {
            console.error("Get Stats error:", e);
            throw e;
        }
    },

    getRSVPs: async () => {
        try {
            const res = await fetch(`${BASE_URL}/admin/rsvps`, { headers: getHeaders() });
            return await handleResponse(res);
        } catch (error) {
            console.error("Get RSVPs error:", error);
            throw error;
        }
    },

    deleteRSVP: async (id: string) => {
        try {
            const res = await fetch(`${BASE_URL}/admin/rsvps/${id}`, {
                method: 'DELETE',
                headers: getHeaders()
            });
            return await handleResponse(res);
        } catch (error) {
            console.error("Delete RSVP error:", error);
            throw error;
        }
    },

    getMedia: async () => {
        try {
            const res = await fetch(`${BASE_URL}/admin/media`, { headers: getHeaders() });
            return await handleResponse(res);
        } catch (error) {
            console.error("Get Media error:", error);
            throw error;
        }
    },

    deleteMedia: async (filename: string) => {
        try {
            const res = await fetch(`${BASE_URL}/admin/media/${filename}`, {
                method: 'DELETE',
                headers: getHeaders()
            });
            return await handleResponse(res);
        } catch (error) {
            console.error("Delete Media error:", error);
            throw error;
        }
    },

    uploadFile: async (file: File, onProgress?: (p: number) => void) => {
        return new Promise((resolve, reject) => {
            const xhr = new XMLHttpRequest();
            const formData = new FormData();
            formData.append('image', file);

            xhr.upload.addEventListener('progress', (e) => {
                if (e.lengthComputable && onProgress) {
                    onProgress(Math.round((e.loaded / e.total) * 100));
                }
            });

            xhr.onload = () => {
                if (xhr.status >= 200 && xhr.status < 300) {
                    try {
                        resolve(JSON.parse(xhr.responseText));
                    } catch (e) {
                        reject(new Error('Invalid JSON response from server'));
                    }
                } else {
                    try {
                        const err = JSON.parse(xhr.responseText);
                        reject(new Error(err.message || 'Upload failed'));
                    } catch (e) {
                        reject(new Error(`Upload failed: ${xhr.status}`));
                    }
                }
            };

            xhr.onerror = () => reject(new Error('Network error'));

            xhr.open('POST', `${BASE_URL}/upload`);
            xhr.setRequestHeader('Authorization', localStorage.getItem('admin_token') || '');
            xhr.send(formData);
        });
    }
};

import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import cors from 'cors';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = 5000;
const DB_PATH = path.join(__dirname, 'database.json');
const UPLOAD_DIR = path.join(__dirname, 'image');

// Ensure DB and Upload folder exist
if (!fs.existsSync(UPLOAD_DIR)) fs.mkdirSync(UPLOAD_DIR);
if (!fs.existsSync(DB_PATH)) {
    const initialDB = {
        users: [{ id: 'admin-1', username: 'admin', password: 'admin123', role: 'superadmin' }],
        rsvps: [],
        messages: [],
        config: null
    };
    fs.writeFileSync(DB_PATH, JSON.stringify(initialDB, null, 2));
}

app.use(cors());
app.use(express.json());
app.use("/image", express.static(UPLOAD_DIR));

// Helper: Read/Write DB
const readDB = () => JSON.parse(fs.readFileSync(DB_PATH, 'utf-8'));
const writeDB = (data) => fs.writeFileSync(DB_PATH, JSON.stringify(data, null, 2));

// Simple Mock JWT & Security Middleware
const verifyToken = (req, res, next) => {
    // LOGIN SYSTEM DISABLED: Always allow access
    req.user = { role: 'superadmin' };
    next();
};

// --- AUTH ROUTES ---
app.post('/api/admin/login', (req, res) => {
    // Login route kept for compatibility but technically not needed
    res.json({ token: 'mock-jwt-token', user: { username: 'admin', role: 'superadmin' } });
});

// --- ADMIN API ROUTES ---

// 1. Stats
app.get('/api/admin/stats', verifyToken, (req, res) => {
    try {
        const db = readDB();
        const stats = {
            totalRSVPs: db.rsvps.length,
            totalGuests: db.rsvps.reduce((acc, curr) => acc + (curr.guestsCount || 0), 0),
            totalMessages: db.messages.length,
            trafficData: [
                { name: 'Mon', visits: 400 }, { name: 'Tue', visits: 300 },
                { name: 'Wed', visits: 600 }, { name: 'Thu', visits: 800 },
                { name: 'Fri', visits: 500 }, { name: 'Sat', visits: 900 },
                { name: 'Sun', visits: 1000 }
            ]
        };
        res.json(stats);
    } catch (error) {
        res.status(500).json({ message: "Failed to fetch stats" });
    }
});

// 2. RSVP Management
app.get('/api/admin/rsvps', verifyToken, (req, res) => {
    try {
        res.json(readDB().rsvps);
    } catch (error) {
        res.status(500).json({ message: "Failed to read RSVPs" });
    }
});

app.delete('/api/admin/rsvps/:id', verifyToken, (req, res) => {
    try {
        const db = readDB();
        db.rsvps = db.rsvps.filter(r => r.id !== req.params.id);
        writeDB(db);
        res.json({ success: true });
    } catch (error) {
        res.status(500).json({ message: "Failed to delete RSVP" });
    }
});

// 3. User Feedback from Frontend (Public)
app.post('/api/public/rsvp', (req, res) => {
    try {
        const db = readDB();
        const newRSVP = { ...req.body, id: Date.now().toString(), createdAt: new Date() };
        db.rsvps.push(newRSVP);
        writeDB(db);
        res.json({ success: true });
    } catch (error) {
        res.status(500).json({ message: "Failed to save RSVP" });
    }
});

// 4. File Upload (Multer)
const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, 'image/'),
    filename: (req, file, cb) => {
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
    }
});
const upload = multer({ storage, limits: { fileSize: 50 * 1024 * 1024 } }); // Increased limit to 50MB for videos

app.post('/api/upload', verifyToken, upload.single('image'), (req, res) => {
    if (!req.file) return res.status(400).send('No file uploaded.');
    res.json({ success: true, imageUrl: `/image/${req.file.filename}` });
});

// 5. Media Library Routes (New)
app.get('/api/admin/media', verifyToken, (req, res) => {
    fs.readdir(UPLOAD_DIR, (err, files) => {
        if (err) {
            console.error(err);
            return res.status(500).json({ message: 'Failed to scan directory' });
        }

        const media = files.map(file => {
            try {
                const stats = fs.statSync(path.join(UPLOAD_DIR, file));
                return {
                    name: file,
                    url: `/image/${file}`,
                    type: /\.(mp4|mkv|mov|webm)$/i.test(file) ? 'video' : 'image',
                    size: stats.size,
                    createdAt: stats.birthtime
                };
            } catch (e) {
                return null;
            }
        })
        .filter(Boolean) // Remove nulls
        .sort((a, b) => b.createdAt - a.createdAt); // Newest first

        res.json(media);
    });
});

app.delete('/api/admin/media/:filename', verifyToken, (req, res) => {
    const safeFilename = path.basename(req.params.filename); // Security: prevent directory traversal
    const filepath = path.join(UPLOAD_DIR, safeFilename);

    if (fs.existsSync(filepath)) {
        try {
            fs.unlinkSync(filepath);
            res.json({ success: true });
        } catch (e) {
            res.status(500).json({ message: 'Error deleting file' });
        }
    } else {
        res.status(404).json({ message: 'File not found' });
    }
});

// Global Error Handler
app.use((err, req, res, next) => {
    console.error("Server Error:", err);
    if (err instanceof multer.MulterError) {
        return res.status(400).json({ message: `Upload error: ${err.message}` });
    }
    res.status(500).json({ message: "Internal Server Error" });
});

app.listen(PORT, '127.0.0.1', () => {
    console.log(`🚀 Production Admin Server: http://127.0.0.1:${PORT}`);
});

