        res.json({ success: true });
    } catch (error) {
        res.status(500).json({ message: "Failed to save RSVP" });
    }
});

// 4. File Upload (Multer)
const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, 'image/'),
    filename: (req, file, cb) => {
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
    }
});
const upload = multer({ storage, limits: { fileSize: 50 * 1024 * 1024 } });

app.post('/api/upload', verifyToken, upload.single('image'), (req, res) => {
    if (!req.file) return res.status(400).send('No file uploaded.');
    res.json({ success: true, imageUrl: `/image/${req.file.filename}` });
});

// 5. Media Library Routes
app.get('/api/admin/media', verifyToken, (req, res) => {
    fs.readdir(UPLOAD_DIR, (err, files) => {
        if (err) {
            console.error("Media Read Error:", err);
            return res.status(500).json({ message: 'Failed to scan directory' });
        }

        const media = files.map(file => {
            try {
                const stats = fs.statSync(path.join(UPLOAD_DIR, file));
                return {
                    name: file,
                    url: `/image/${file}`,
                    type: /\.(mp4|mkv|mov|webm)$/i.test(file) ? 'video' : 'image',
                    size: stats.size,
                    createdAt: stats.birthtime
                };
            } catch (e) {
                return null;
            }
        })
        .filter(Boolean)
        .sort((a, b) => b.createdAt - a.createdAt);

        res.json(media);
    });
});

app.delete('/api/admin/media/:filename', verifyToken, (req, res) => {
    const safeFilename = path.basename(req.params.filename);
    const filepath = path.join(UPLOAD_DIR, safeFilename);

    if (fs.existsSync(filepath)) {
        try {
            fs.unlinkSync(filepath);
            res.json({ success: true });
        } catch (e) {
            res.status(500).json({ message: 'Error deleting file' });
        }
    } else {
        res.status(404).json({ message: 'File not found' });
    }
});

// Global Error Handler
app.use((err, req, res, next) => {
    console.error("Server Error:", err);
    if (err instanceof multer.MulterError) {
        return res.status(400).json({ message: `Upload error: ${err.message}` });
    }
    res.status(500).json({ message: "Internal Server Error" });
});

