import React, { useEffect, useState } from 'react';
import { getWebsiteConfig, saveWebsiteConfig } from '../services/storage';
import { uploadImage } from '../services/api';
import { WebsiteConfig } from '../types';
import { Save, Upload, Loader2, Trash2, Edit3, Image as ImageIcon } from 'lucide-react';

const AdminDashboard: React.FC = () => {
  const [config, setConfig] = useState<WebsiteConfig | null>(null);
  const [saving, setSaving] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<{ [key: string]: number }>({});

  useEffect(() => {
    const fetchData = async () => {
      try {
        const configData = await getWebsiteConfig();
        setConfig(configData);
      } catch (err) {
        console.error("Config fetch error", err);
      }
    };
    fetchData();
  }, []);

  const handleConfigChange = (section: keyof WebsiteConfig, field: string, value: any, index?: number) => {
    if (!config) return;

    setConfig(prev => {
      if (!prev) return null;
      const newConfig = { ...prev };

      if (section === 'stories' && typeof index === 'number') {
        newConfig.stories = [...prev.stories];
        newConfig.stories[index] = { ...newConfig.stories[index], [field]: value };
      } else if (section === 'events' && typeof index === 'number') {
        newConfig.events = [...prev.events];
        newConfig.events[index] = { ...newConfig.events[index], [field]: value };
      } else if (section === 'hero') {
        newConfig.hero = { ...prev.hero, [field]: value };
      } else if (section === 'contact') {
        newConfig.contact = { ...prev.contact, [field]: value };
      } else if (section === 'countdownDate') {
         newConfig.countdownDate = value;
      }
      return newConfig;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, section: string, index?: number) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const key = `${section}-${index ?? 'main'}`;
    setUploadProgress(prev => ({ ...prev, [key]: 0 }));

    try {
      const response = await uploadImage(file, (percent) => {
        setUploadProgress(prev => ({ ...prev, [key]: percent }));
      });

      if (response.success && response.imageUrl) {
        const finalUrl = response.imageUrl; 

        if (section === 'gallery') {
           setConfig(prev => {
               if(!prev) return null;
               return { ...prev, gallery: [...prev.gallery, finalUrl] }
           });
        } else if (section === 'hero') {
           handleConfigChange('hero', 'image', finalUrl);
        } else if (section === 'stories' && typeof index === 'number') {
           handleConfigChange('stories', 'image', finalUrl, index);
        }
      } else {
        alert(response.message || "আপলোড ব্যর্থ হয়েছে।");
      }
    } catch (error: any) {
      console.error("Upload error", error);
      alert(error.message || "সার্ভারের সাথে যোগাযোগ করতে সমস্যা হচ্ছে।");
    } finally {
      setTimeout(() => {
        setUploadProgress(prev => {
          const next = { ...prev };
          delete next[key];
          return next;
        });
      }, 1000);
    }
  };

  const removeGalleryImage = (index: number) => {
    setConfig(prev => {
        if(!prev) return null;
        const newGallery = prev.gallery.filter((_, i) => i !== index);
        return { ...prev, gallery: newGallery };
    });
  };

  const saveContent = async () => {
    if (!config) return;
    setSaving(true);
    const success = await saveWebsiteConfig(config);
    setSaving(false);

    if (success) {
      alert('পরিবর্তন সংরক্ষণ করা হয়েছে!');
    } else {
      alert('সংরক্ষণ ব্যর্থ হয়েছে!');
    }
  };

  const ProgressOverlay = ({ percent }: { percent: number }) => (
    <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center text-white rounded z-20">
      <Loader2 className="animate-spin mb-2" size={24} />
      <span className="text-xs font-bold">{percent}%</span>
      <div className="w-4/5 h-1 bg-gray-700 mt-2 rounded-full overflow-hidden">
        <div className="h-full bg-emerald-500 transition-all duration-300" style={{ width: `${percent}%` }}></div>
      </div>
    </div>
  );

  const isVideo = (url: string) => url?.toLowerCase().match(/\.(mp4|mkv|webm)$/);

  if (!config) return <div className="flex h-96 items-center justify-center"><Loader2 className="animate-spin text-wedding-primary" size={48} /></div>;

  return (
    <div className="space-y-8 animate-fade-in pb-20">
      <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-slate-100 sticky top-4 z-20">
        <div>
           <h1 className="text-2xl font-bold text-slate-900">ওয়েবসাইট এডিটর</h1>
           <p className="text-slate-500 text-sm">ওয়েবসাইটের কন্টেন্ট পরিবর্তন করুন</p>
        </div>
        <button 
          onClick={saveContent} 
          disabled={saving} 
          className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-3 rounded-xl hover:bg-emerald-700 disabled:opacity-50 transition-all shadow-lg shadow-emerald-600/20 font-bold"
        >
          {saving ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />} 
          {saving ? 'সংরক্ষণ হচ্ছে...' : 'সেভ করুন'}
        </button>
      </div>

      {/* Hero Section */}
      <section className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-center gap-3 mb-6 border-b pb-4">
             <div className="p-2 bg-rose-100 text-rose-600 rounded-lg"><Edit3 size={20} /></div>
             <h3 className="text-xl font-bold text-slate-800">হিরো সেকশন (Hero)</h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">বরের নাম</label>
                    <input type="text" value={config.hero.groomName} onChange={e => handleConfigChange('hero', 'groomName', e.target.value)} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-rose-500/20 outline-none" />
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">কনের নাম</label>
                    <input type="text" value={config.hero.brideName} onChange={e => handleConfigChange('hero', 'brideName', e.target.value)} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-rose-500/20 outline-none" />
                 </div>
              </div>
              <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">তারিখ</label>
                  <input type="text" value={config.hero.date} onChange={e => handleConfigChange('hero', 'date', e.target.value)} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-rose-500/20 outline-none" />
              </div>
              <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Countdown Date (ISO)</label>
                  <input type="datetime-local" value={config.countdownDate} onChange={e => handleConfigChange('countdownDate', '', e.target.value)} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-rose-500/20 outline-none" />
              </div>
              <div>
                  <label className="block text-xs font-bold text-slate-500 uppercase mb-1">লোকেশন</label>
                  <input type="text" value={config.hero.location} onChange={e => handleConfigChange('hero', 'location', e.target.value)} className="w-full px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-rose-500/20 outline-none" />
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase mb-2">কভার ছবি / ভিডিও</label>
              <div className="relative h-64 w-full rounded-xl border-2 border-dashed border-slate-300 bg-slate-50 overflow-hidden flex flex-col items-center justify-center group hover:border-rose-400 transition-colors">
                 {config.hero.image ? (
                   isVideo(config.hero.image) ? (
                     <video src={config.hero.image} className="h-full w-full object-cover" muted playsInline autoPlay loop />
                   ) : (
                     <img src={config.hero.image} alt="Hero" className="h-full w-full object-cover" />
                   )
                 ) : (
                   <div className="text-center p-4">
                     <ImageIcon className="mx-auto text-slate-300 mb-2" size={32} />
                     <p className="text-sm text-slate-400">কোন ছবি নেই</p>
                   </div>
                 )}

                 <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <label className="cursor-pointer bg-white text-slate-800 px-4 py-2 rounded-lg font-bold shadow-lg transform translate-y-2 group-hover:translate-y-0 transition-transform">
                      <input type="file" className="hidden" onChange={(e) => handleImageUpload(e, 'hero')} />
                      পরিবর্তন করুন
                    </label>
                 </div>
                 {uploadProgress['hero-main'] !== undefined && <ProgressOverlay percent={uploadProgress['hero-main']} />}
              </div>
              <p className="text-xs text-slate-400 mt-2 text-center">সুপারিশ: 1920x1080px হাই কোয়ালিটি ইমেজ বা ভিডিও</p>
            </div>
          </div>
      </section>

      {/* Gallery Section */}
      <section className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
        <div className="flex items-center gap-3 mb-6 border-b pb-4">
            <div className="p-2 bg-rose-100 text-rose-600 rounded-lg"><ImageIcon size={20} /></div>
            <h3 className="text-xl font-bold text-slate-800">গ্যালারি</h3>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
          {config.gallery.map((src, idx) => (
            <div key={idx} className="relative group aspect-square bg-slate-100 rounded-xl overflow-hidden shadow-sm">
              {isVideo(src) ? (
                <video src={src} className="w-full h-full object-cover" />
              ) : (
                <img src={src} alt="gallery" className="w-full h-full object-cover" />
              )}
              <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                 <button onClick={() => removeGalleryImage(idx)} className="p-2 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors">
                   <Trash2 size={18} />
                 </button>
              </div>
            </div>
          ))}

          <label className="cursor-pointer border-2 border-dashed border-slate-300 rounded-xl flex flex-col items-center justify-center hover:bg-rose-50 hover:border-rose-300 transition-all aspect-square relative overflow-hidden">
            {uploadProgress['gallery-main'] !== undefined ? (
                <div className="flex flex-col items-center p-4 text-center">
                    <Loader2 className="animate-spin text-rose-500 mb-2" />
                    <span className="text-xs font-bold text-slate-600">{uploadProgress['gallery-main']}%</span>
                </div>
            ) : (
                <>
                  <div className="p-3 bg-slate-100 rounded-full mb-2 group-hover:bg-white transition-colors">
                     <Upload className="text-slate-400 group-hover:text-rose-500" size={24} />
                  </div>
                  <span className="text-xs font-bold text-slate-500 uppercase">আপলোড</span>
                </>
            )}
            <input type="file" className="hidden" onChange={(e) => handleImageUpload(e, 'gallery')} />
          </label>
        </div>
      </section>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Menu, X, Heart } from 'lucide-react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();

  const isHome = location.pathname === '/';

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'হোম', id: 'home' },
    { name: 'আমাদের গল্প', id: 'couple' },
    { name: 'অনুষ্ঠান', id: 'events' },
    { name: 'গ্যালারি', id: 'gallery' },
    { name: 'RSVP', id: 'rsvp' },
    { name: 'যোগাযোগ', id: 'contact' },
  ];

  const toggleMenu = () => setIsOpen(!isOpen);

  const handleNavClick = (id: string) => {
    setIsOpen(false);
    if (!isHome) {
      navigate('/');
      setTimeout(() => {
        document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const navClass = `fixed w-full z-50 transition-all duration-300 ${
    scrolled || !isHome || isOpen
      ? 'bg-white/90 backdrop-blur-md shadow-md py-2' 
      : 'bg-transparent py-4'
  }`;

  const textClass = scrolled || !isHome || isOpen ? 'text-slate-800' : 'text-white';
  const logoClass = scrolled || !isHome || isOpen ? 'text-wedding-primary' : 'text-white';

  return (
    <nav className={navClass}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <div className="flex-shrink-0 cursor-pointer flex items-center gap-2 group" onClick={() => handleNavClick('home')}>
             <div className="relative">
                <Heart className={`fill-current ${logoClass} transition-colors duration-300`} size={28} />
                <Heart className={`absolute top-0 left-0 fill-current ${logoClass} animate-ping opacity-30`} size={28} />
             </div>
             <span className={`text-3xl font-cursive font-bold ${logoClass} transition-colors duration-300`}>
              শুভ বিবাহ
            </span>
          </div>

          <div className="hidden md:block">
            <div className="ml-10 flex items-baseline space-x-6">
              {navLinks.map((link) => (
                <button
                  key={link.name}
                  onClick={() => handleNavClick(link.id)}
                  className={`${textClass} hover:text-wedding-primary px-3 py-2 rounded-full text-base font-semibold transition-all duration-300 hover:bg-white/20`}
                >
                  {link.name}
                </button>
              ))}
            </div>
          </div>

          <div className="-mr-2 flex md:hidden">
            <button
              onClick={toggleMenu}
              type="button"
              className={`p-2 rounded-md ${textClass} hover:text-wedding-primary focus:outline-none`}
            >
              <span className="sr-only">Open main menu</span>
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      <div className={`md:hidden absolute top-full left-0 w-full bg-white/95 backdrop-blur-md border-t transition-all duration-300 origin-top ${isOpen ? 'scale-y-100 opacity-100' : 'scale-y-0 opacity-0'}`}>
        <div className="px-4 pt-4 pb-6 space-y-2 text-center shadow-xl">
          {navLinks.map((link) => (
            <button
              key={link.name}
              onClick={() => handleNavClick(link.id)}
              className="text-slate-800 hover:text-wedding-primary hover:bg-rose-50 block w-full px-3 py-3 rounded-xl text-lg font-medium transition-colors"
            >
              {link.name}
            </button>
          ))}
        </div>
      </div>
    </nav>
  );
};

