                             </div>
                          </div>

                          <div className="flex-1 space-y-4">
                              <div className="grid grid-cols-3 gap-4">
                                  <div className="col-span-1">
                                    <InputGroup label="Year" value={story.year} onChange={(e:any) => handleArrayItemChange('stories', index, 'year', e.target.value)} />
