import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import cors from 'cors';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
// CHANGED PORT TO 5001 to avoid conflicts with other services (like AirPlay on macOS)
const PORT = 5001;
const DB_PATH = path.join(__dirname, 'database.json');
const UPLOAD_DIR = path.join(__dirname, 'image');

// Ensure DB and Upload folder exist
if (!fs.existsSync(UPLOAD_DIR)) fs.mkdirSync(UPLOAD_DIR);
if (!fs.existsSync(DB_PATH)) {
    const initialDB = {
        users: [{ id: 'admin-1', username: 'admin', password: 'admin123', role: 'superadmin' }],
        rsvps: [],
        messages: [],
        config: null
    };
    fs.writeFileSync(DB_PATH, JSON.stringify(initialDB, null, 2));
}

// Middleware
app.use(cors()); // Allow all origins to support direct API calls
app.use(express.json({ limit: '50mb' })); // Increased limit for config
app.use("/image", express.static(UPLOAD_DIR));

// Request Logger (Debug)
app.use((req, res, next) => {
    console.log(`[${new Date().toISOString()}] ${req.method} ${req.url}`);
    next();
});

// Helper: Read/Write DB
const readDB = () => {
    try {
        return JSON.parse(fs.readFileSync(DB_PATH, 'utf-8'));
    } catch (e) {
        console.error("DB Read Error:", e);
        return { users: [], rsvps: [], messages: [], config: null };
    }
};
const writeDB = (data) => fs.writeFileSync(DB_PATH, JSON.stringify(data, null, 2));

// Simple Mock JWT & Security Middleware
const verifyToken = (req, res, next) => {
    // LOGIN SYSTEM DISABLED: Always allow access
    req.user = { role: 'superadmin' };
    next();
};

// --- API ROUTES ---

// Health Check
app.get('/api/health', (req, res) => {
    res.json({ status: 'ok', server: 'running', port: PORT });
});

// Auth (Mock)
app.post('/api/admin/login', (req, res) => {
    res.json({ token: 'mock-jwt-token', user: { username: 'admin', role: 'superadmin' } });
});

// 1. Stats
app.get('/api/admin/stats', verifyToken, (req, res) => {
    try {
        const db = readDB();
        const stats = {
            totalRSVPs: db.rsvps ? db.rsvps.length : 0,
            totalGuests: db.rsvps ? db.rsvps.reduce((acc, curr) => acc + (curr.guestsCount || 0), 0) : 0,
            totalMessages: db.messages ? db.messages.length : 0,
            trafficData: [
                { name: 'Mon', visits: 400 }, { name: 'Tue', visits: 300 },
                { name: 'Wed', visits: 600 }, { name: 'Thu', visits: 800 },
                { name: 'Fri', visits: 500 }, { name: 'Sat', visits: 900 },
                { name: 'Sun', visits: 1000 }
            ]
        };
        res.json(stats);
    } catch (error) {
        console.error("Stats Error:", error);
        res.status(500).json({ message: "Failed to fetch stats" });
    }
});

// 2. RSVP Management
app.get('/api/admin/rsvps', verifyToken, (req, res) => {
    try {
        res.json(readDB().rsvps || []);
    } catch (error) {
        res.status(500).json({ message: "Failed to read RSVPs" });
    }
});

app.delete('/api/admin/rsvps/:id', verifyToken, (req, res) => {
    try {
        const db = readDB();
        db.rsvps = (db.rsvps || []).filter(r => r.id !== req.params.id);
        writeDB(db);
        res.json({ success: true });
    } catch (error) {
        res.status(500).json({ message: "Failed to delete RSVP" });
    }
});

// 3. User Feedback from Frontend (Public)
app.post('/api/public/rsvp', (req, res) => {
    try {
        const db = readDB();
        const newRSVP = { ...req.body, id: Date.now().toString(), createdAt: new Date() };
        if (!db.rsvps) db.rsvps = [];
        db.rsvps.push(newRSVP);
        writeDB(db);
        res.json({ success: true });
    } catch (error) {
        res.status(500).json({ message: "Failed to save RSVP" });
    }
});

// 4. Messages (Public)
app.post('/api/public/message', (req, res) => {
    try {
        const db = readDB();
        const newMsg = { ...req.body, id: Date.now().toString(), createdAt: new Date() };
        if (!db.messages) db.messages = [];
        db.messages.push(newMsg);
        writeDB(db);
        res.json({ success: true });
    } catch (error) {
        res.status(500).json({ message: "Failed to save message" });
    }
});

// 5. Messages (Admin)
app.get('/api/admin/messages', verifyToken, (req, res) => {
    try {
        res.json(readDB().messages || []);
    } catch (error) {
        res.status(500).json({ message: "Failed to read messages" });
    }
});

// 6. Website Config (Public Read)
app.get('/api/public/config', (req, res) => {
    try {
        const db = readDB();
        res.json(db.config);
    } catch (error) {
        res.status(500).json({ message: "Failed to read config" });
    }
});

// 7. Website Config (Admin Save)
app.post('/api/admin/config', verifyToken, (req, res) => {
    try {
        const db = readDB();
        db.config = req.body;
        writeDB(db);
        res.json({ success: true });
    } catch (error) {
        console.error(error);
        res.status(500).json({ message: "Failed to save config" });
    }
});

// 8. File Upload (Multer)
const storage = multer.diskStorage({
    destination: (req, file, cb) => cb(null, 'image/'),
    filename: (req, file, cb) => {
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        cb(null, file.fieldname + '-' + uniqueSuffix + path.extname(file.originalname));
    }
});
const upload = multer({ storage, limits: { fileSize: 50 * 1024 * 1024 } });

app.post('/api/upload', verifyToken, upload.single('image'), (req, res) => {
    if (!req.file) return res.status(400).send('No file uploaded.');
    // Construct full URL
    const baseUrl = `${req.protocol}://${req.get('host')}`;
    res.json({ success: true, imageUrl: `${baseUrl}/image/${req.file.filename}` });
});

// 9. Media Library Routes
app.get('/api/admin/media', verifyToken, (req, res) => {
    fs.readdir(UPLOAD_DIR, (err, files) => {
        if (err) {
            console.error("Media Read Error:", err);
            return res.status(500).json({ message: 'Failed to scan directory' });
        }

        // Construct full URL helper
        const baseUrl = `${req.protocol}://${req.get('host')}`;

        const media = files.map(file => {
            try {
                const stats = fs.statSync(path.join(UPLOAD_DIR, file));
                return {
                    name: file,
                    url: `${baseUrl}/image/${file}`, // Return absolute URL
                    type: /\.(mp4|mkv|mov|webm)$/i.test(file) ? 'video' : 'image',
                    size: stats.size,
                    createdAt: stats.birthtime
                };
            } catch (e) {
                return null;
            }
        })
        .filter(Boolean)
        .sort((a, b) => b.createdAt - a.createdAt);

        res.json(media);
    });
});

app.delete('/api/admin/media/:filename', verifyToken, (req, res) => {
    const safeFilename = path.basename(req.params.filename);
    const filepath = path.join(UPLOAD_DIR, safeFilename);

    if (fs.existsSync(filepath)) {
        try {
            fs.unlinkSync(filepath);
            res.json({ success: true });
        } catch (e) {
            res.status(500).json({ message: 'Error deleting file' });
        }
    } else {
        res.status(404).json({ message: 'File not found' });
    }
});

// Catch-all 404 for API routes
app.use('/api/*', (req, res) => {
    res.status(404).json({ message: `API Route not found: ${req.method} ${req.originalUrl}` });
});

// Global Error Handler
app.use((err, req, res, next) => {
    console.error("Server Error:", err);
    if (err instanceof multer.MulterError) {
        return res.status(400).json({ message: `Upload error: ${err.message}` });
    }
    res.status(500).json({ message: "Internal Server Error" });
});

// Listen on all interfaces
app.listen(PORT, '0.0.0.0', () => {
    console.log(`🚀 Production Admin Server running on port ${PORT}`);
    console.log(`   - API Health: http://127.0.0.1:${PORT}/api/health`);
    console.log(`   - Ensure frontend adminApi.ts uses port ${PORT}`);
});

